  // Liquid bleach (12.5%) needs more product than cal-hypo for the same ppm.
  const bleach = computePoolTurnover({ pool_volume_gal: 20000, turnover_hr: 6, chlorine_ppm: 2, chlorine_type: "liquid_bleach" });
