test("bounds: calc-hvac computeChillerTons pins Q = gpm*factor*dT and tons = Q/12000 on the 240 gpm / 10 F water example", () => {
  const r = computeChillerTons({ gpm: 240, ewt_F: 54, lwt_F: 44, fluid: "water" });
  assert.strictEqual(r.delta_T_F, 10);
  assert.strictEqual(r.factor, 500);
  assert.strictEqual(r.q_btu_hr, 240 * 500 * 10);
  assert.ok(Math.abs(r.tons - 100) < 1e-9);
  assert.ok(Math.abs(r.kw - (240 * 500 * 10) / 3412) < 1e-9);
  // Glycol lowers the factor (and the tonnage) for the same flow / delta-T.
  const g = computeChillerTons({ gpm: 240, ewt_F: 54, lwt_F: 44, fluid: "glycol_30" });
  assert.ok(g.tons < r.tons);
  // Required flow at nameplate inverts the identity.
  const np = computeChillerTons({ gpm: 240, ewt_F: 54, lwt_F: 44, fluid: "water", nameplate_tons: 100 });
  assert.ok(Math.abs(np.required_gpm - 240) < 1e-6);
  // Rejections.
  assert.ok("error" in computeChillerTons({ gpm: 0, ewt_F: 54, lwt_F: 44 }));
  assert.ok("error" in computeChillerTons({ gpm: 240, ewt_F: 44, lwt_F: 54 }));
});

test("bounds: calc-hvac computeHxLmtdNtu pins LMTD, Q, UA, effectiveness, NTU on the counter-flow Incropera example", () => {
  const r = computeHxLmtdNtu({ config: "counterflow", th_in_F: 200, th_out_F: 100, tc_in_F: 60, tc_out_F: 140, hot_gpm: 50, cold_gpm: 62.5 });
  assert.ok(Math.abs(r.lmtd_F - (20 / Math.log(1.5))) < 1e-6);
  assert.strictEqual(r.q_btu_hr, 50 * 500 * 100);
  assert.ok(Math.abs(r.ua_btu_hr_F - r.q_btu_hr / r.lmtd_F) < 1e-6);
  assert.ok(Math.abs(r.effectiveness - 2500000 / 3500000) < 1e-6);
  assert.ok(Math.abs(r.ntu - r.ua_btu_hr_F / 25000) < 1e-6);
  assert.ok(Math.abs(r.c_ratio - 0.8) < 1e-9);
  // Parallel-flow (outlets must not cross): 200->120 hot, 60->100 cold.
  const cf = computeHxLmtdNtu({ config: "counterflow", th_in_F: 200, th_out_F: 120, tc_in_F: 60, tc_out_F: 100, hot_gpm: 50, cold_gpm: 50 });
  const p = computeHxLmtdNtu({ config: "parallel", th_in_F: 200, th_out_F: 120, tc_in_F: 60, tc_out_F: 100, hot_gpm: 50, cold_gpm: 50 });
  assert.ok(p.lmtd_F < cf.lmtd_F);
  // Rejections: hot warms up, cold cools down, cold outlet above hot inlet.
  assert.ok("error" in computeHxLmtdNtu({ th_in_F: 100, th_out_F: 120, tc_in_F: 60, tc_out_F: 80 }));
  assert.ok("error" in computeHxLmtdNtu({ th_in_F: 200, th_out_F: 100, tc_in_F: 80, tc_out_F: 60 }));
  assert.ok("error" in computeHxLmtdNtu({ th_in_F: 200, th_out_F: 100, tc_in_F: 60, tc_out_F: 220 }));
});

test("bounds: calc-hvac computeAirChangesPerHour pins ACH = cfm*60/vol with pressurization and target bands", () => {
  const r = computeAirChangesPerHour({ volume_ft3: 10000, supply_cfm: 1000, occupancy: "classroom" });
  assert.ok(Math.abs(r.ach - 6) < 1e-9);
  assert.ok(Math.abs(r.net_ach - 6) < 1e-9);
  assert.strictEqual(r.pressurization_cfm, 0);
  assert.ok(/within/.test(r.comparison));
  // Lower return -> positive pressurization and a smaller net ACH.
  const p = computeAirChangesPerHour({ volume_ft3: 10000, supply_cfm: 1000, return_cfm: 800, occupancy: "classroom" });
  assert.ok(p.pressurization_cfm > 0);
  assert.ok(p.net_ach < p.ach);
  // Rejections.
  assert.ok("error" in computeAirChangesPerHour({ volume_ft3: 0, supply_cfm: 100 }));
  assert.ok("error" in computeAirChangesPerHour({ volume_ft3: 1000, supply_cfm: 0 }));
});

test("bounds: calc-hvac computeBoilerPipeSizing pins GPM = Q/(500*dT), velocity-limited size, and Hazen-Williams head on the 200 kBTU example", () => {
  const r = computeBoilerPipeSizing({ boiler_btu_hr: 200000, delta_T_F: 20, material: "copper", max_velocity_fps: 4, length_ft: 100 });
  assert.ok(Math.abs(r.gpm - 20) < 1e-9);
  // 1-1/4 in (ID 1.265) exceeds 4 ft/s at 20 gpm, so the tile steps up to 1-1/2 in.
  assert.strictEqual(r.recommended_size, "1-1/2");
  assert.ok(r.velocity_fps <= 4);
  assert.ok(Math.abs(r.velocity_fps - 20 / (2.44778 * 1.505 * 1.505)) < 1e-6);
  assert.ok(r.friction_ft_per_100ft > 0);
  // 100 ft run -> head equals the per-100-ft friction.
  assert.ok(Math.abs(r.head_ft - r.friction_ft_per_100ft) < 1e-9);
  // Steel's higher ceiling and larger ID pick a smaller or equal size at the same flow.
  const steel = computeBoilerPipeSizing({ boiler_btu_hr: 200000, delta_T_F: 20, material: "steel" });
  assert.ok(steel.velocity_fps <= steel.max_velocity_fps);
  // Rejections.
  assert.ok("error" in computeBoilerPipeSizing({ boiler_btu_hr: 0, delta_T_F: 20 }));
  assert.ok("error" in computeBoilerPipeSizing({ boiler_btu_hr: 200000, delta_T_F: 0 }));
});

test("bounds: calc-hvac computeCompressorShortCycle pins the cycling parabola and the oversized single-stage short-cycle flag", () => {
  const r = computeCompressorShortCycle({ system_type: "single", load_fraction_pct: 50 });
  assert.ok(Math.abs(r.cph_estimated - 6) < 1e-9); // peaks at the 6 cph ceiling at 50% load
  assert.ok(Math.abs(r.on_time_min - 5) < 1e-9);
  assert.ok(Math.abs(r.off_time_min - 5) < 1e-9);
  assert.strictEqual(r.min_runtime_min, 10);
  assert.strictEqual(r.short_cycling, true); // 5 min on < 10 min oil-return runtime
  // Cycle rate falls toward the endpoints (parabola).
  const q = computeCompressorShortCycle({ system_type: "single", load_fraction_pct: 25 });
  assert.ok(q.cph_estimated < r.cph_estimated);
  // Inverter modulates: no fixed ceiling, no parabola.
  const inv = computeCompressorShortCycle({ system_type: "inverter", load_fraction_pct: 50 });
  assert.strictEqual(inv.max_cph, null);
  assert.strictEqual(inv.cph_estimated, null);
  // Observed cph above the ceiling flags short-cycling.
  const obs = computeCompressorShortCycle({ system_type: "single", load_fraction_pct: 85, observed_cph: 9 });
  assert.strictEqual(obs.short_cycling, true);
  // Rejections.
  assert.ok("error" in computeCompressorShortCycle({ system_type: "single", load_fraction_pct: 0 }));
  assert.ok("error" in computeCompressorShortCycle({ system_type: "single", load_fraction_pct: 100 }));
});

test("bounds: calc-hvac computeHumidifierCapacity pins addition = 60*CFM*rho*dW and latent = addition*1061 on the 1000 CFM 20->40 RH example", () => {
  const r = computeHumidifierCapacity({ cfm: 1000, supply_db_F: 70, entering_rh_pct: 20, target_rh_pct: 40, altitude_ft: 0 });
  assert.ok(r.W_target > r.W_entering);
  assert.ok(Math.abs(r.addition_lb_hr - 60 * 1000 * r.air_density_lb_ft3 * r.delta_W) < 1e-6);
  assert.ok(Math.abs(r.latent_btu_hr - r.addition_lb_hr * 1061) < 1e-6);
  assert.ok(Math.abs(r.gpd - (r.addition_lb_hr * 24) / 8.34) < 1e-6);
  // Sanity: ~14 lb/hr, ~40 gpd for these conditions.
  assert.ok(r.addition_lb_hr > 12 && r.addition_lb_hr < 16);
  // Altitude lowers pressure -> higher humidity ratio for the same RH -> more moisture.
  const high = computeHumidifierCapacity({ cfm: 1000, supply_db_F: 70, entering_rh_pct: 20, target_rh_pct: 40, altitude_ft: 5000 });
  assert.ok(high.delta_W > r.delta_W);
  // Rejections.
  assert.ok("error" in computeHumidifierCapacity({ cfm: 0, supply_db_F: 70, entering_rh_pct: 20, target_rh_pct: 40 }));
  assert.ok("error" in computeHumidifierCapacity({ cfm: 1000, supply_db_F: 70, entering_rh_pct: 40, target_rh_pct: 20 }));
});

test("bounds: calc-hvac computeFilterPressureDrop pins airflow, velocity-scaled drops, and the brake-HP fan power on the MERV 13 example", () => {
  const r = computeFilterPressureDrop({ filter_type: "merv13", face_area_ft2: 4, face_velocity_fpm: 300, fan_total_efficiency: 0.6, runtime_hr_per_year: 4000 });
  assert.ok(Math.abs(r.airflow_cfm - 1200) < 1e-9);
  assert.ok(Math.abs(r.clean_dp_in_wc - 0.35) < 1e-9);
  assert.ok(Math.abs(r.final_dp_in_wc - 0.70) < 1e-9);
  assert.ok(Math.abs(r.clean_fan_kw - (1200 * 0.35 / 6356 / 0.6) * 0.7457) < 1e-9);
  // Average drop drives the annual energy; the penalty is over clean.
  assert.ok(Math.abs(r.annual_fan_kwh - r.avg_fan_kw * 4000) < 1e-6);
  assert.ok(Math.abs(r.annual_penalty_kwh - (r.avg_fan_kw - r.clean_fan_kw) * 4000) < 1e-6);
  // Drops scale linearly with face velocity from the 300 fpm reference.
  const fast = computeFilterPressureDrop({ filter_type: "merv13", face_area_ft2: 4, face_velocity_fpm: 600 });
  assert.ok(Math.abs(fast.clean_dp_in_wc - 0.70) < 1e-9);
  assert.ok(fast.warnings.some((w) => /500/.test(w)));
  // Override path and rejections.
  const ov = computeFilterPressureDrop({ filter_type: "merv8", face_area_ft2: 10, face_velocity_fpm: 300, clean_dp_override: 0.15, final_dp_override: 0.5, energy_cost_per_kwh: 0.13 });
  assert.ok(Math.abs(ov.clean_dp_in_wc - 0.15) < 1e-9 && Math.abs(ov.annual_fan_cost - ov.annual_fan_kwh * 0.13) < 1e-6);
  assert.ok("error" in computeFilterPressureDrop({ face_area_ft2: 0, face_velocity_fpm: 300 }));
  assert.ok("error" in computeFilterPressureDrop({ face_area_ft2: 4, face_velocity_fpm: 300, fan_total_efficiency: 0 }));
});

test("bounds: calc-hvac computeInsulationHeatLoss pins Q_bare > Q_insulated with effectiveness in 0-100 % for the spec 2.375 in / 1.5 in fiberglass example", () => {
  const r = computeInsulationHeatLoss({ pipe_OD_in: 2.375, surface_T_F: 200, ambient_T_F: 70, air_velocity_fpm: 0, insulation: "fiberglass", thickness_in: 1.5 });
  assert.ok(r.Q_bare_BTU_hr_ft > r.Q_insulated_BTU_hr_ft);
  assert.ok(r.effectiveness_pct > 0 && r.effectiveness_pct < 100);
  assert.strictEqual(r.k_value, 0.025);
  assert.ok(r.outer_surface_T_F < 200 && r.outer_surface_T_F > 70);
  // Zero-thickness path -> Q approaches bare.
  const zero = computeInsulationHeatLoss({ pipe_OD_in: 2.375, surface_T_F: 200, ambient_T_F: 70, air_velocity_fpm: 0, insulation: "fiberglass", thickness_in: 0 });
  assert.ok(Number.isFinite(zero.Q_insulated_BTU_hr_ft));
  // Rejections.
  assert.ok("error" in computeInsulationHeatLoss({ pipe_OD_in: 0, surface_T_F: 200, ambient_T_F: 70 }));
  assert.ok("error" in computeInsulationHeatLoss({ pipe_OD_in: 2, surface_T_F: 200, ambient_T_F: 70, thickness_in: -1 }));
  assert.ok("error" in computeInsulationHeatLoss({ pipe_OD_in: 2, surface_T_F: 200, ambient_T_F: 70, insulation: "no-such" }));
});

test("bounds: calc-hvac computeDuctLeakage pins leak per 100 ft^2 at 1 in WC and SMACNA effective-class lookup on the spec 1200/1140 / 600 ft^2 example", () => {
  const r = computeDuctLeakage({ design_cfm: 1200, measured_cfm: 1140, duct_surface_ft2: 600, test_pressure_inwc: 1.0, design_class: 6 });
  assert.strictEqual(r.leakage_cfm, 60);
  assert.strictEqual(r.leakage_pct, 5);
  assert.strictEqual(r.leak_at_1inwc, 60);
  assert.strictEqual(r.leak_per_100ft2, 10);
  assert.strictEqual(r.effective_class, 12); // 10 > 6 but <= 12.
  assert.strictEqual(r.pass, false);
  // Rejections.
  assert.ok("error" in computeDuctLeakage({ design_cfm: 0, measured_cfm: 0, duct_surface_ft2: 600 }));
  assert.ok("error" in computeDuctLeakage({ design_cfm: 1200, measured_cfm: -1, duct_surface_ft2: 600 }));
  assert.ok("error" in computeDuctLeakage({ design_cfm: 1200, measured_cfm: 1140, duct_surface_ft2: 0 }));
  assert.ok("error" in computeDuctLeakage({ design_cfm: 1200, measured_cfm: 1140, duct_surface_ft2: 600, test_pressure_inwc: 0 }));
  assert.ok("error" in computeDuctLeakage({ design_cfm: 1200, measured_cfm: 1140, duct_surface_ft2: 600, design_class: 99 }));
});

test("bounds: calc-hvac computeOutdoorAirVentilation pins ASHRAE 62.1 Vbz = Rp*Pz + Ra*Az on the spec 25 ppl / 2500 ft^2 office example", () => {
  const r = computeOutdoorAirVentilation({ Rp_cfm_per_person: 5, Ra_cfm_per_ft2: 0.06, people: 25, floor_area_ft2: 2500, Ez: 1.0 });
  assert.strictEqual(r.Vbz_cfm, 5 * 25 + 0.06 * 2500); // 275.
  assert.strictEqual(r.Voz_cfm, 275);
  assert.strictEqual(r.cfm_per_person, 11);
  assert.ok(Math.abs(r.cfm_per_ft2 - 275 / 2500) < 1e-9);
  assert.ok(Array.isArray(r.warnings) && r.warnings.length >= 1);
  // E_z < 1 reduces Voz (i.e. Voz > Vbz).
  const lowEz = computeOutdoorAirVentilation({ Rp_cfm_per_person: 5, Ra_cfm_per_ft2: 0.06, people: 25, floor_area_ft2: 2500, Ez: 0.8 });
  assert.ok(Math.abs(lowEz.Voz_cfm - 275 / 0.8) < 1e-9);
  // Rejections.
  assert.ok("error" in computeOutdoorAirVentilation({ Rp_cfm_per_person: 5, Ra_cfm_per_ft2: 0.06, people: 0, floor_area_ft2: 2500, Ez: 1.0 }));
  assert.ok("error" in computeOutdoorAirVentilation({ Rp_cfm_per_person: 5, Ra_cfm_per_ft2: 0.06, people: 25, floor_area_ft2: 0, Ez: 1.0 }));
  assert.ok("error" in computeOutdoorAirVentilation({ Rp_cfm_per_person: 5, Ra_cfm_per_ft2: 0.06, people: 25, floor_area_ft2: 2500, Ez: 0 }));
  assert.ok("error" in computeOutdoorAirVentilation({ Rp_cfm_per_person: -1, Ra_cfm_per_ft2: 0.06, people: 25, floor_area_ft2: 2500, Ez: 1.0 }));
});

test("bounds: calc-hvac computeHoodExhaust pins IMC 507.13 Q = cfm_per_ft * L for the spec 8 ft wall-canopy heavy-duty hood (3200 cfm)", () => {
  const r = computeHoodExhaust({ hood_class: "I", hood_type: "wall-canopy", duty: "heavy", length_ft: 8, duct_velocity_fpm: 1500 });
  assert.strictEqual(r.Q_exhaust_cfm, 3200);
  assert.strictEqual(r.cfm_per_ft, 400);
  assert.strictEqual(r.makeup_cfm, 2560); // 0.80 * 3200.
  assert.ok(Math.abs(r.duct_area_in2 - (3200 / 1500) * 144) < 1e-9);
  assert.strictEqual(r.grease_duct_slope_in_per_ft, 0.25);
  // Type II vapor-only: 100 cfm/ft flat.
  const t2 = computeHoodExhaust({ hood_class: "II", length_ft: 6, width_ft: 4, duct_velocity_fpm: 1500 });
  assert.strictEqual(t2.cfm_per_ft, 100);
  assert.strictEqual(t2.Q_exhaust_cfm, 600);
  // Rejections.
  assert.ok("error" in computeHoodExhaust({ hood_class: "I", hood_type: "wall-canopy", duty: "heavy", length_ft: 0 }));
  assert.ok("error" in computeHoodExhaust({ hood_class: "III", length_ft: 8 }));
  assert.ok("error" in computeHoodExhaust({ hood_class: "II", length_ft: 6 })); // width missing
  assert.ok("error" in computeHoodExhaust({ hood_class: "I", hood_type: "not-real", duty: "heavy", length_ft: 8 }));
  assert.ok("error" in computeHoodExhaust({ hood_class: "I", hood_type: "backshelf", duty: "extra-heavy", length_ft: 8 })); // disallowed duty
});

test("bounds: calc-hvac computeSHRLatent pins Q_s = 1.08 * CFM * (T_ra - T_sa) * rho on the spec 36k Btu/hr / 1200 cfm sea-level example", () => {
  const r = computeSHRLatent({ total_capacity_btu_hr: 36000, return_db_F: 75, return_wb_F: 63, supply_db_F: 55, cfm: 1200, altitude_ft: 0 });
  assert.strictEqual(r.rho_ratio, 1);
  assert.ok(Math.abs(r.Q_sensible_btu_hr - 1.08 * 1200 * (75 - 55) * 1.0) < 1e-9);
  assert.ok(Math.abs(r.Q_latent_btu_hr - (36000 - r.Q_sensible_btu_hr)) < 1e-9);
  assert.ok(Math.abs(r.SHR - r.Q_sensible_btu_hr / 36000) < 1e-9);
  assert.ok(r.W_ra_gpp > 0);
  assert.ok(r.W_sa_gpp >= 0);
  // Rejections.
  assert.ok("error" in computeSHRLatent({ total_capacity_btu_hr: 0, cfm: 1200 }));
  assert.ok("error" in computeSHRLatent({ total_capacity_btu_hr: 36000, cfm: 0 }));
  assert.ok("error" in computeSHRLatent({ total_capacity_btu_hr: 36000, return_db_F: 75, return_wb_F: 80, supply_db_F: 55, cfm: 1200 }));
  assert.ok("error" in computeSHRLatent({ total_capacity_btu_hr: 36000, return_db_F: 75, return_wb_F: 63, supply_db_F: 80, cfm: 1200 }));
});

test("bounds: calc-hvac render* sentinels - every exported renderer is a callable function (DOM not mocked here)", () => {
  // Renderers build DOM via document.createElement; calling them requires
  // a DOM environment. Per spec-v14 §8.4 the bounds-fuzzer's substring
  // check is satisfied by the symbol import; the per-renderer interactive
  // smoke tests live in the Playwright suite. This sentinel keeps the
  // render symbols pinned and asserts each is wired.
  for (const fn of [
    renderRefrigerantCharge, renderApproachDeltaT, renderOutdoorAirMix,
    renderEquivalentLength, renderWetBulbPsychrometer, renderInsulationThickness,
    renderCompareRefrigerants, renderEvaporativeCooling, renderManualJCooling,
    renderManualJHeating, renderDuctSizing, renderStaticPressureHvac,
    renderRefrigerantPT, renderSuperheatSubcool, renderSeerEer,
    renderBalancePoint, renderSHR, renderCfmPerTon, renderCombustionAir,
    renderCombustionAirMaxInput, renderOutdoorAirVentilation,
  ]) {
    assert.strictEqual(typeof fn, "function", "render symbol must be a function");
  }
});

test("bounds: calc-powerquality v20 A.1/A.2/A.3 pin constants + reject non-finite/out-of-range", () => {
  // A.1 parallel-conductor-derate
  const a1 = computeParallelConductorDerate({ i_single_A: 200, n_sets: 3, conductor_size: "3/0" });
  assert.ok(Math.abs(a1.i_total_A - 600) < 0.5);
  assert.ok(Number.isFinite(a1.adjustment_factor));
  assert.ok("error" in computeParallelConductorDerate({ i_single_A: Infinity, n_sets: 3 }));
  assert.ok("error" in computeParallelConductorDerate({ i_single_A: 200, n_sets: 3, conductor_size: "12" }));
  assert.ok("error" in computeParallelConductorDerate({ i_single_A: 200, n_sets: 3, ambient_factor: 0 }));
  // A.2 neutral-current-3ph
  const a2 = computeNeutralCurrent3ph({ ia_A: 100, ib_A: 80, ic_A: 60 });
  assert.ok(Math.abs(a2.neutral_A - 34.641) < 0.05);
  assert.ok(Number.isFinite(a2.neutral_A));
  assert.ok("error" in computeNeutralCurrent3ph({ ia_A: 0, ib_A: 0, ic_A: 0 }));
  assert.ok("error" in computeNeutralCurrent3ph({ ia_A: -1, ib_A: 0, ic_A: 0 }));
  assert.ok(Number.isFinite(computeNeutralCurrent3ph({ ia_A: 1e6, ib_A: 0, ic_A: 0 }).neutral_A));
  // A.3 motor-vd-starting
  const a3 = computeMotorVdStarting({ source_voltage_V: 480, length_ft: 250, cmils: 250000, lrc_A: 180, phase: "three", k_const: 12.9 });
  assert.ok(Math.abs(a3.dip_pct - 0.838) < 0.01);
  assert.ok(Number.isFinite(a3.v_terminal_V));
  assert.ok("error" in computeMotorVdStarting({ source_voltage_V: 0, length_ft: 250, cmils: 250000, lrc_A: 180 }));
  assert.ok("error" in computeMotorVdStarting({ source_voltage_V: 480, length_ft: 250, cmils: 0, lrc_A: 180 }));
  assert.ok("error" in computeMotorVdStarting({ source_voltage_V: 480, length_ft: Infinity, cmils: 250000, lrc_A: 180 }));
});


