  assert.strictEqual(r.fall_limited_ft, 1.5 / 0.25); // 6
  assert.strictEqual(r.max_length_ft, 5); // min of 5 and 6
  // Tight slope -> fall-limited wins.
  const tight = computeTrapArm({ pipe_diameter_in: 3, slope_in_per_ft: 0.5 });
