  assert.ok("error" in _m2({ ph: 7.5, temp: 25, ca_mgl: 0, alk_mgl: 150, tds_mgl: 320 }));
  assert.ok(Math.abs(_m3({ flow_mgd: 0.5, dose_mgl: 8, strength_pct: 12.5, sg: 1.16, pump_max_gpd: 50 }).setting_pct - 55.2) < 0.5);
