test("bounds: spec-v51 lighting-beam pins beam diameter + inverse-square illuminance + reject non-finite", () => {
  // 20 deg beam, 30 ft throw, 100000 cd -> 10.5796 ft pool, 111.11 fc, 1196 lux
  const a = _cn4({ beam_angle_deg: 20, throw_distance: 30, distance_unit: "ft", source: "candela", candela: 100000 });
  assert.ok(Math.abs(a.beam_diameter_ft - 2 * 30 * Math.tan(10 * Math.PI / 180)) < 1e-9);
  assert.ok(Math.abs(a.illuminance_fc - 100000 / 900) < 1e-6);
  assert.ok(Math.abs(a.illuminance_lux - a.illuminance_fc * 10.76391041670972) < 1e-3);
  // double the throw -> quarter the illuminance (inverse-square)
  const b = _cn4({ beam_angle_deg: 20, throw_distance: 60, distance_unit: "ft", source: "candela", candela: 100000 });
  assert.ok(Math.abs(b.illuminance_fc - a.illuminance_fc / 4) < 1e-6);
  // lumens mode derives candela from the beam solid angle
  const c = _cn4({ beam_angle_deg: 20, throw_distance: 10, distance_unit: "m", source: "lumens", lumens: 20000 });
  assert.ok(c.candela_derived === true && Math.abs(c.candela - 20000 / (2 * Math.PI * (1 - Math.cos(10 * Math.PI / 180)))) < 1e-3);
  assert.ok("error" in _cn4({ beam_angle_deg: 0, throw_distance: 30, candela: 100 }));
  assert.ok("error" in _cn4({ beam_angle_deg: 180, throw_distance: 30, candela: 100 }));
  assert.ok("error" in _cn4({ beam_angle_deg: 20, throw_distance: 0, candela: 100 }));
  assert.ok("error" in _cn4({ beam_angle_deg: 20, throw_distance: 30, source: "candela", candela: 0 }));
  assert.ok("error" in _cn4({ beam_angle_deg: 20, throw_distance: 30, source: "lumens", lumens: 0 }));
  assert.ok("error" in _cn4({ beam_angle_deg: Infinity, throw_distance: 30, candela: 100 }));
});

test("bounds: spec-v676 computeLightingThrowForPool pins throw = D/(2 tan(angle/2)), round-trips through computeLightingBeam across angles and units, and error seams", () => {
  const r = _v676({ target_pool_diameter: 10.579619, beam_angle_deg: 20, distance_unit: "ft" });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.throw_distance - 10.579619 / (2 * Math.tan(10 * Math.PI / 180))) < 1e-9, `throw identity: ${r.throw_distance}`);
  assert.ok(Math.abs(r.throw_distance - 30) < 1e-4, `pinned 30 ft: ${r.throw_distance}`);
  // A wider beam reaches the same pool from a shorter throw.
  const wide = _v676({ target_pool_diameter: 10.579619, beam_angle_deg: 40, distance_unit: "ft" });
  assert.ok(wide.throw_distance < r.throw_distance, `wider beam shorter throw: ${wide.throw_distance}`);
  // Round-trip: the throw, fed back through the forward tile, reproduces the target pool diameter (in the same unit).
  for (const beam_angle_deg of [10, 26, 50]) {
    for (const [unit, key] of [["ft", "beam_diameter_ft"], ["m", "beam_diameter_m"]]) {
      const D = 8;
      const m = _v676({ target_pool_diameter: D, beam_angle_deg, distance_unit: unit });
      assert.ok(!m.error, `sweep ang=${beam_angle_deg} ${unit}: ${JSON.stringify(m)}`);
      assertFinite(m.throw_distance, "throw"); assert.ok(m.throw_distance > 0, "throw positive");
      const back = _cn4({ beam_angle_deg, throw_distance: m.throw_distance, distance_unit: unit, source: "candela", candela: 1000 });
      assert.ok(Math.abs(back[key] - D) < 1e-9, `round-trip ang=${beam_angle_deg} ${unit}: ${back[key]}`);
    }
  }
  // Error seams: non-positive diameter, beam angle out of range, non-finite.
  assert.ok("error" in _v676({ target_pool_diameter: 0, beam_angle_deg: 20 }));
  assert.ok("error" in _v676({ target_pool_diameter: 10, beam_angle_deg: 0 }));
  assert.ok("error" in _v676({ target_pool_diameter: 10, beam_angle_deg: 180 }));
  assert.ok("error" in _v676({ target_pool_diameter: Infinity, beam_angle_deg: 20 }));
});

test("bounds: spec-v43 tank-volume pins horizontal segment + vertical + reject non-finite", () => {
  // horizontal 24 in dia x 48 in, half full (depth 12) -> 47.0015 gal, 50%, full 94.003 gal
  const h = _ctv({ orientation: "horizontal", linear_unit: "in", diameter: 24, length: 48, depth: 12 });
  assert.ok(Math.abs(h.volume_gal - 47.00149) < 1e-3);
  assert.ok(Math.abs(h.full_gal - 94.00298) < 1e-3);
  assert.ok(Math.abs(h.percent_full - 50) < 1e-6);
  // full depth -> 100%; feet units equivalent to the inch half-fill
  assert.ok(Math.abs(_ctv({ orientation: "horizontal", linear_unit: "in", diameter: 24, length: 48, depth: 24 }).percent_full - 100) < 1e-9);
  assert.ok(Math.abs(_ctv({ orientation: "horizontal", linear_unit: "ft", diameter: 2, length: 4, depth: 1 }).volume_gal - 47.00149) < 1e-3);
  // vertical: V = pi R^2 h -> depth 12 of 48 = 25%
  const v = _ctv({ orientation: "vertical", linear_unit: "in", diameter: 24, length: 48, depth: 12 });
  assert.ok(Math.abs(v.percent_full - 25) < 1e-9);
  // depth beyond ceiling clamps to full (note), does not leak
  assert.ok(_ctv({ orientation: "horizontal", linear_unit: "in", diameter: 24, length: 48, depth: 30 }).percent_full === 100);
  assert.ok("error" in _ctv({ diameter: 0, length: 48, depth: 12 }));
  assert.ok("error" in _ctv({ diameter: 24, length: 48, depth: -1 }));
  assert.ok("error" in _ctv({ diameter: Infinity, length: 48, depth: 12 }));
});

test("bounds: spec-v24/v25 conduit, civil, audio, and surveying tiles pin constants + reject non-finite", () => {
  // conduit-offset: 6 in @ 30 deg -> 12 in spacing, multiplier 2.0; angle 0 rejected (cosecant blowup)
  assert.ok(Math.abs(_co1({ offset_in: 6, angle_deg: 30 }).mark_spacing_in - 12) < 1e-6);
  assert.ok(Math.abs(_co1({ offset_in: 6, angle_deg: 30 }).multiplier - 2) < 1e-6);
  assert.ok("error" in _co1({ offset_in: 6, angle_deg: 0 }));
  assert.ok("error" in _co1({ offset_in: 6, angle_deg: Infinity }));
  // conduit-saddle: 3 in @ 45/22.5 -> 7.5 in spacing, 0.5625 in shrink; depth 0 rejected
  assert.ok(Math.abs(_co2({ mode: "three-point", depth_in: 3, preset: "45/22.5" }).mark_spacing_in - 7.5) < 1e-6);
  assert.ok("error" in _co2({ mode: "three-point", depth_in: 0, preset: "45/22.5" }));
  // conduit-90-stub: 8 in stub, 6 in deduct -> 2 in mark; 5 deg shots -> 18 shots; height 0 rejected
  assert.strictEqual(_co3({ mode: "stub-up", height_in: 8, deduct_in: 6 }).mark_in, 2);
  assert.strictEqual(_co3({ mode: "segment-90", radius_in: 10, per_shot_deg: 5 }).n_shots, 18);
  assert.ok("error" in _co3({ mode: "stub-up", height_in: 0, deduct_in: 6 }));
  // weld-heat-input: 25 V 200 A 8 in/min eta 0.8 -> 37500 J/in arc, 30 kJ/in HI; TS 0 rejected
  assert.strictEqual(_ce1({ process: "SMAW", voltage_V: 25, current_A: 200, travel_in_min: 8, efficiency: 0.8 }).arc_energy_j_in, 37500);
  assert.ok(Math.abs(_ce1({ process: "SMAW", voltage_V: 25, current_A: 200, travel_in_min: 8, efficiency: 0.8 }).heat_input_kj_in - 30) < 1e-9);
  assert.ok("error" in _ce1({ process: "SMAW", voltage_V: 25, current_A: 200, travel_in_min: 0, efficiency: 0.8 }));
  // metal-weight: 1x12x120 plate @0.2836 -> 408.384 lb; ID>=OD tube rejected
  assert.ok(Math.abs(_ce2({ shape: "plate", width_in: 12, thickness_in: 1, length_in: 120, quantity: 1, density_lb_in3: 0.2836 }).weight_per_piece_lb - 408.384) < 1e-3);
  assert.ok("error" in _ce2({ shape: "round-tube", dia_in: 2, id_in: 2, length_in: 10, quantity: 1, density_lb_in3: 0.2836 }));
  // layout-squaring: 3,4 -> 5; side 0 rejected
  assert.strictEqual(_ce3({ mode: "find-diagonal", side_a: 3, side_b: 4 }).ideal_diagonal, 5);
  assert.ok("error" in _ce3({ mode: "find-diagonal", side_a: 0, side_b: 4 }));
  // horizontal-curve: R 1000 delta 30 -> T 267.95, D 5.7296; R 0 rejected
  assert.ok(Math.abs(_ce4({ mode: "radius", radius_ft: 1000, delta_deg: 30 }).tangent_ft - 267.9492) < 1e-3);
  assert.ok(Math.abs(_ce4({ mode: "radius", radius_ft: 1000, delta_deg: 30 }).degree_of_curve - 5.72958) < 1e-4);
  assert.ok("error" in _ce4({ mode: "radius", radius_ft: 0, delta_deg: 30 }));
  // vertical-curve: crest -> BVC 94, turning 97.6; L 0 rejected
  assert.ok(Math.abs(_ce5({ g1_pct: 3, g2_pct: -2, length_ft: 400, pvi_station_ft: 5000, pvi_elevation_ft: 100 }).turning_elev_ft - 97.6) < 1e-6);
  assert.ok("error" in _ce5({ g1_pct: 3, g2_pct: -2, length_ft: 0, pvi_station_ft: 5000, pvi_elevation_ft: 100 }));
  // earthwork-end-area: [100,100] @100 -> 10000 ft3, 370.37 yd3; interval 0 rejected
  assert.strictEqual(_ce6({ areas: [100, 100], interval_ft: 100 }).total_ft3, 10000);
  assert.ok(Math.abs(_ce6({ areas: [100, 100], interval_ft: 100 }).total_yd3 - 370.3704) < 1e-3);
  assert.ok("error" in _ce6({ areas: [100, 100], interval_ft: 0 }));
  // slope-stake-cut-fill: 104.5/100 -> 4.5 cut, catch 9; ratio 0 rejected
  assert.strictEqual(_ce7({ existing_elev_ft: 104.5, design_elev_ft: 100, slope_ratio_h: 2, offset_at_hinge_ft: 0 }).cut_fill_ft, 4.5);
  assert.strictEqual(_ce7({ existing_elev_ft: 104.5, design_elev_ft: 100, slope_ratio_h: 2, offset_at_hinge_ft: 0 }).catch_offset_ft, 9);
  assert.ok("error" in _ce7({ existing_elev_ft: 104.5, design_elev_ft: 100, slope_ratio_h: 0 }));
  // rolling-offset: 12,9 -> 15 true offset; angle 0 rejected
  assert.strictEqual(_cg1({ rise_in: 12, roll_in: 9, angle_deg: 45 }).true_offset_in, 15);
  assert.ok("error" in _cg1({ rise_in: 12, roll_in: 9, angle_deg: 0 }));
  // speaker-impedance: four 8-ohm parallel -> 2 ohm; z<=0 rejected
  assert.strictEqual(_cn1({ topology: "parallel", z_ohm: 8, count: 4 }).z_total_ohm, 2);
  assert.ok("error" in _cn1({ topology: "parallel", z_ohm: 0, count: 4 }));
  // decibel-converter: P2/P1=2 -> 3.0103 dB; zero arg rejected
  assert.ok(Math.abs(_cn2({ mode: "power-ratio", p1: 1, p2: 2 }).db - 3.0103) < 1e-3);
  assert.ok("error" in _cn2({ mode: "power-ratio", p1: 1, p2: 0 }));
  // amp-power-spl: 90 dB, 100 W, 1 m -> 110 dB; distance 0 rejected
  assert.strictEqual(_cn3({ sensitivity_db: 90, power_w: 100, distance_m: 1 }).spl_db, 110);
  assert.ok("error" in _cn3({ sensitivity_db: 90, power_w: 100, distance_m: 0 }));
  // area-by-coordinates: 100x100 square -> 10000 ft2; <3 points rejected
  assert.strictEqual(_cp1({ points: [{ n: 0, e: 0 }, { n: 0, e: 100 }, { n: 100, e: 100 }, { n: 100, e: 0 }] }).area_ft2, 10000);
  assert.ok("error" in _cp1({ points: [{ n: 0, e: 0 }, { n: 0, e: 100 }] }));
  // traverse-closure: open 2-course -> misclosure 141.42, denom 1.414; rectangle -> perfect closure (denom null, no Infinity)
  assert.ok(Math.abs(_cp2({ courses: [{ azimuth_deg: 0, distance: 100 }, { azimuth_deg: 90, distance: 100 }] }).linear_misclosure - 141.4214) < 1e-3);
  const _rect = _cp2({ courses: [{ azimuth_deg: 0, distance: 100 }, { azimuth_deg: 90, distance: 200 }, { azimuth_deg: 180, distance: 100 }, { azimuth_deg: 270, distance: 200 }] });
  assert.strictEqual(_rect.relative_precision_denominator, null);
  assert.ok(Number.isFinite(_rect.sum_lat) && Number.isFinite(_rect.sum_dep));
  assert.ok("error" in _cp2({ courses: [{ azimuth_deg: 0, distance: 100 }] }));
});

test("bounds: spec-v767 curve-deflection-stakeout pins the deflection/chord, the degree mode, cross-checks horizontal-curve, and error seams", () => {
  // Spec example: R 500, arc 100 -> delta = (100/1000)(180/pi) = 5.72958 deg; chord = 1000 sin(0.1) = 99.833; D = 11.4592.
  const r = _v767({ mode: "radius", radius_ft: 500, arc_length_ft: 100 });
  assert.ok(Math.abs(r.deflection_deg - (0.1 * 180 / Math.PI)) < 1e-9);
  assert.ok(Math.abs(r.deflection_deg - 5.729578) < 1e-4);
  assert.ok(Math.abs(r.chord_ft - 1000 * Math.sin(0.1)) < 1e-9);
  assert.ok(Math.abs(r.chord_ft - 99.83342) < 1e-4);
  assert.ok(Math.abs(r.degree_of_curve - 5729.58 / 500) < 1e-9);
  // Degree mode resolves the same radius: D = 11.45916 -> R = 500.
  const d = _v767({ mode: "degree", degree_of_curve: 5729.58 / 500, arc_length_ft: 100 });
  assert.ok(Math.abs(d.radius_ft - 500) < 1e-6);
  assert.ok(Math.abs(d.deflection_deg - r.deflection_deg) < 1e-9);
  // Cross-check horizontal-curve: an arc length equal to the full curve length L = R*delta_rad gives a
  // deflection of exactly half the central angle (the PT closure property of the deflection method).
  for (let i = 0; i < 120; i++) {
    const R = 100 + i * 25;
    const centralDeg = 5 + (i % 60);          // total central angle 5..64 deg
    const L = R * (centralDeg * Math.PI / 180); // full curve length
    const st = _v767({ mode: "radius", radius_ft: R, arc_length_ft: L });
    assert.ok(!st.error);
    assert.ok(Math.abs(st.deflection_deg - centralDeg / 2) < 1e-9, "PT deflection = half the central angle");
    // The full-curve sub-chord equals horizontal-curve's long chord for the same delta.
    const hc = _ce4({ mode: "radius", radius_ft: R, delta_deg: centralDeg });
    assert.ok(Math.abs(st.chord_ft - hc.long_chord_ft) < 1e-6, "full-arc chord = long chord");
  }
  // Monotonicity: a longer arc from the same PC turns a larger deflection.
  assert.ok(_v767({ mode: "radius", radius_ft: 500, arc_length_ft: 200 }).deflection_deg
    > _v767({ mode: "radius", radius_ft: 500, arc_length_ft: 100 }).deflection_deg);
  // Error seams.
  assert.ok("error" in _v767({ mode: "radius", radius_ft: 0, arc_length_ft: 100 }));
  assert.ok("error" in _v767({ mode: "degree", degree_of_curve: 0, arc_length_ft: 100 }));
  assert.ok("error" in _v767({ mode: "radius", radius_ft: 500, arc_length_ft: 0 }));
  assert.ok("error" in _v767({ mode: "radius", radius_ft: Infinity, arc_length_ft: 100 }));
});

