  assert.ok("error" in _cv54a({ spring_angle_deg: 90, corner_angle_deg: 90 }));
  assert.ok("error" in _cv54a({ spring_angle_deg: 38, corner_angle_deg: 0 }));
  assert.ok("error" in _cv54a({ spring_angle_deg: 38, corner_angle_deg: 180 }));
