// ---------------------------------------------------------------------------
// spec-v28 low-voltage / data / security cabling (calc-lowvoltage.js): fiber
// loss budget, cable-tray fill, CCTV storage, 70 V line, standby battery, coax
// loss. Each pinned at its worked example + a degenerate input that must
// { error } rather than leak a non-finite field (length, tray width, bitrate,
// V^2/P impedance, battery period, coax loss-coefficient seams).
// ---------------------------------------------------------------------------
import {
  computeFiberLossBudget as _cv28z1, computeCableTrayFill as _cv28z2, computeCctvStorage as _cv28z3, computeFiberMaxLength as _v693,
  computeSpeaker70vLine as _cv28z4, computeStandbyBatterySizing as _cv28z5, computeCoaxRgLoss as _cv28z6, computeStandbyBatteryRuntime as _v687,
  computeCctvRetentionDays as _v696,
} from "../../calc-lowvoltage.js";

test("bounds: spec-v28 low-voltage cabling tiles pin constants + reject non-finite", () => {
  // fiber-loss-budget: 300 m OM4 + 2 connectors -> 2.4 dB; length 0 rejected
  assert.ok(Math.abs(_cv28z1({ length_m: 300, attenuation_db_km: 3.0, connector_count: 2, loss_per_connector_db: 0.75, splice_count: 0, max_channel_loss_db: 2.6 }).total_loss_db - 2.4) < 1e-6);
  assert.ok("error" in _cv28z1({ length_m: 0, attenuation_db_km: 3 }));
  // cable-tray-fill: six 1.5 in 4/0 in 12 in tray -> 9 in fill; width 0 rejected
  assert.strictEqual(_cv28z2({ tray_type: "ladder", tray_width_in: 12, cables: [{ count: 6, diameter_in: 1.5, large: true }] }).fill_value, 9);
  assert.ok("error" in _cv28z2({ tray_width_in: 0, cables: [{ count: 1, diameter_in: 1 }] }));
  // cctv-storage: 1 cam 4 Mbps 24h 30d -> 1296 GB; bitrate 0 rejected
  assert.strictEqual(_cv28z3({ camera_count: 1, bitrate_mbps: 4, recording_mode: "continuous", retention_days: 30 }).total_storage_gb, 1296);
  assert.ok("error" in _cv28z3({ camera_count: 1, bitrate_mbps: 0, retention_days: 30 }));
  // speaker-70v-line: 16x8 W -> 128 W, Z = 70.7^2/128 ~ 39 ohm; rating 0 rejected; zero load -> finite (null Z, no divide-by-zero)
  assert.strictEqual(_cv28z4({ amp_rated_w: 200, headroom_percent: 20, tap_watts: 8, tap_count: 16, line_voltage_v: 70.7 }).total_tap_w, 128);
  assert.ok(Math.abs(_cv28z4({ amp_rated_w: 200, headroom_percent: 20, tap_watts: 8, tap_count: 16, line_voltage_v: 70.7 }).reflected_impedance_ohm - 39.05) < 0.1);
  assert.strictEqual(_cv28z4({ amp_rated_w: 200, headroom_percent: 20, tap_watts: 0, tap_count: 0, line_voltage_v: 70.7 }).reflected_impedance_ohm, null);
  assert.ok("error" in _cv28z4({ amp_rated_w: 0, tap_watts: 8, tap_count: 16, line_voltage_v: 70.7 }));
  // standby-battery-sizing: 0.5x24 + 2x5min, derate 1.2 -> 14.6 Ah; negative period rejected
  assert.ok(Math.abs(_cv28z5({ standby_current_a: 0.5, standby_hours: 24, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 }).required_ah - 14.6) < 0.05);
  assert.ok("error" in _cv28z5({ standby_current_a: -1, standby_hours: 24, alarm_current_a: 2, alarm_minutes: 5 }));
  // coax-rg-loss: 100 ft @ 6 dB/100ft -> 6 dB; length 0 rejected; max-run guards zero loss coef
  assert.strictEqual(_cv28z6({ mode: "loss", loss_per_100ft_db: 6, length_ft: 100, source_level: 0 }).total_loss_db, 6);
  assert.ok("error" in _cv28z6({ mode: "loss", loss_per_100ft_db: 6, length_ft: 0 }));
  assert.ok("error" in _cv28z6({ mode: "max-run", loss_per_100ft_db: 0, source_level: 0, target_level: -6 }));
});

test("bounds: spec-v693 computeFiberMaxLength pins len = 1000(budget - fixed)/att, round-trips through computeFiberLossBudget, and error seams", () => {
  const r = _v693({ max_channel_loss_db: 2.6, attenuation_db_km: 3.0, connector_count: 2, loss_per_connector_db: 0.75, splice_count: 0 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.max_length_m - 1000 * (2.6 - 1.5) / 3.0) < 1e-9, `length identity: ${r.max_length_m}`);
  assert.ok(Math.abs(r.max_length_m - 366.6667) < 1e-3, `pinned 366.7 m: ${r.max_length_m}`);
  // Single-mode's lower attenuation reaches farther for the same budget.
  const smf = _v693({ max_channel_loss_db: 2.6, attenuation_db_km: 0.4, connector_count: 2, loss_per_connector_db: 0.75 });
  assert.ok(smf.max_length_m > r.max_length_m, `smf farther: ${smf.max_length_m}`);
  // Round-trip: at the max length the forward tile's total loss equals the budget (margin 0).
  for (const max_channel_loss_db of [1.5, 2.6, 5.0]) {
    for (const attenuation_db_km of [0.4, 1.5, 3.5]) {
      // 1 connector (0.75 dB fixed) keeps room under the smallest 1.5 dB budget.
      const m = _v693({ max_channel_loss_db, attenuation_db_km, connector_count: 1, loss_per_connector_db: 0.75, splice_count: 0, loss_per_splice_db: 0.3 });
      assert.ok(!m.error, `sweep max=${max_channel_loss_db} att=${attenuation_db_km}: ${JSON.stringify(m)}`);
      assertFinite(m.max_length_m, "len"); assert.ok(m.max_length_m > 0, "len positive");
      const back = _cv28z1({ length_m: m.max_length_m, attenuation_db_km, connector_count: 1, loss_per_connector_db: 0.75, splice_count: 0, loss_per_splice_db: 0.3, max_channel_loss_db });
      assert.ok(Math.abs(back.total_loss_db - max_channel_loss_db) < 1e-9, `round-trip max=${max_channel_loss_db} att=${attenuation_db_km}: ${back.total_loss_db}`);
    }
  }
  // Error seams: non-positive budget / attenuation, fixed losses alone meet the budget, non-finite.
  assert.ok("error" in _v693({ max_channel_loss_db: 0, attenuation_db_km: 3 }));
  assert.ok("error" in _v693({ max_channel_loss_db: 2.6, attenuation_db_km: 0 }));
  assert.ok("error" in _v693({ max_channel_loss_db: 1.0, attenuation_db_km: 3, connector_count: 2, loss_per_connector_db: 0.75 }));
  assert.ok("error" in _v693({ max_channel_loss_db: NaN, attenuation_db_km: 3 }));
});

test("bounds: spec-v687 computeStandbyBatteryRuntime pins Hs = (Ah/derate - alarm_Ah)/Is, round-trips through computeStandbyBatterySizing, and error seams", () => {
  const r = _v687({ battery_ah: 14.6, standby_current_a: 0.5, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.standby_hours - (14.6 / 1.2 - 2.0 * 5 / 60) / 0.5) < 1e-9, `Hs identity: ${r.standby_hours}`);
  assert.ok(Math.abs(r.standby_hours - 24) < 0.05, `pinned 24 h: ${r.standby_hours}`);
  // A larger battery holds the standby load longer.
  const big = _v687({ battery_ah: 18, standby_current_a: 0.5, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 });
  assert.ok(big.standby_hours > r.standby_hours, `bigger longer: ${big.standby_hours}`);
  // Round-trip: the standby hours, fed back through the forward tile, reproduce the battery capacity (as required_ah).
  for (const battery_ah of [7, 14.6, 40]) {
    for (const standby_current_a of [0.25, 0.5, 1.0]) {
      const m = _v687({ battery_ah, standby_current_a, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 });
      assert.ok(!m.error, `sweep Ah=${battery_ah} Is=${standby_current_a}: ${JSON.stringify(m)}`);
      assertFinite(m.standby_hours, "Hs"); assert.ok(m.standby_hours > 0, "Hs positive");
      const back = _cv28z5({ standby_current_a, standby_hours: m.standby_hours, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 });
      assert.ok(Math.abs(back.required_ah - battery_ah) < 1e-6, `round-trip Ah=${battery_ah} Is=${standby_current_a}: ${back.required_ah}`);
    }
  }
  // Error seams: non-positive capacity / standby current / derate, too-small battery (no standby time), non-finite.
  assert.ok("error" in _v687({ battery_ah: 0, standby_current_a: 0.5 }));
  assert.ok("error" in _v687({ battery_ah: 14.6, standby_current_a: 0 }));
  assert.ok("error" in _v687({ battery_ah: 14.6, standby_current_a: 0.5, derate: 0 }));
  assert.ok("error" in _v687({ battery_ah: 0.1, standby_current_a: 0.5, alarm_current_a: 2.0, alarm_minutes: 5, derate: 1.2 }));
  assert.ok("error" in _v687({ battery_ah: NaN, standby_current_a: 0.5 }));
});

test("bounds: spec-v696 computeCctvRetentionDays pins days = disk/(n*br*0.45*hours), round-trips through computeCctvStorage, and error seams", () => {
  const r = _v696({ disk_capacity_gb: 16000, camera_count: 8, bitrate_mbps: 4, recording_mode: "continuous" });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.retention_days - 16000 / (8 * 4 * 0.45 * 24)) < 1e-9, `days identity: ${r.retention_days}`);
  assert.ok(Math.abs(r.retention_days - 46.2963) < 1e-3, `pinned 46.30 days: ${r.retention_days}`);
  // Motion recording halves the hours, so the same disk holds twice the days.
  const m = _v696({ disk_capacity_gb: 16000, camera_count: 8, bitrate_mbps: 4, recording_mode: "motion", motion_duty_percent: 50 });
  assert.ok(Math.abs(m.retention_days - 2 * r.retention_days) < 1e-6, `motion doubles: ${m.retention_days}`);
  // Round-trip: at the reported retention the forward tile's total storage equals the disk capacity.
  for (const disk_capacity_gb of [2000, 16000, 100000]) {
    for (const bitrate_mbps of [1, 4, 12]) {
      for (const camera_count of [1, 8, 64]) {
        const s = _v696({ disk_capacity_gb, camera_count, bitrate_mbps, recording_mode: "continuous" });
        assert.ok(!s.error, `sweep disk=${disk_capacity_gb} br=${bitrate_mbps} n=${camera_count}: ${JSON.stringify(s)}`);
        assertFinite(s.retention_days, "days"); assert.ok(s.retention_days > 0, "days positive");
        const back = _cv28z3({ camera_count, bitrate_mbps, recording_mode: "continuous", retention_days: s.retention_days });
        assert.ok(Math.abs(back.total_storage_gb - disk_capacity_gb) < 1e-6, `round-trip disk=${disk_capacity_gb} br=${bitrate_mbps} n=${camera_count}: ${back.total_storage_gb}`);
      }
    }
  }
  // Error seams: non-positive disk, zero bitrate, zero cameras, bad motion duty, non-finite.
  assert.ok("error" in _v696({ disk_capacity_gb: 0, camera_count: 8, bitrate_mbps: 4 }));
  assert.ok("error" in _v696({ disk_capacity_gb: 16000, camera_count: 8, bitrate_mbps: 0 }));
  assert.ok("error" in _v696({ disk_capacity_gb: 16000, camera_count: 0, bitrate_mbps: 4 }));
  assert.ok("error" in _v696({ disk_capacity_gb: 16000, camera_count: 8, bitrate_mbps: 4, recording_mode: "motion", motion_duty_percent: 0 }));
  assert.ok("error" in _v696({ disk_capacity_gb: Infinity, camera_count: 8, bitrate_mbps: 4 }));
});

// ---------------------------------------------------------------------------
// spec-v29 pipe / raceway field-layout bench: cold-spring (thermal growth +
// gap), PVC raceway expansion (NEC 352.44), insulated pipe rack spacing. Each
// pins its worked example and rejects non-finite / non-positive inputs.
// ---------------------------------------------------------------------------
import {
  computeColdSpring as _cv29p1, computeRacewayExpansion as _cv29p2, computePipeSpacingRack as _cv29p3,
} from "../../calc-pipefit.js";

test("bounds: spec-v29 pipe/raceway field-layout tiles pin constants + reject bad input", () => {
  // pipe-cold-spring: steel 100 ft 50->250 F -> 1.56 in growth, 0.78 in gap at 50%; length 0 rejected; equal temps -> 0 growth (finite, not error)
  assert.ok(Math.abs(_cv29p1({ material: "steel", run_length_ft: 100, install_temp_f: 50, operating_temp_f: 250, cold_spring_percent: 50 }).thermal_growth_in - 1.56) < 1e-6);
  assert.ok(Math.abs(_cv29p1({ material: "steel", run_length_ft: 100, install_temp_f: 50, operating_temp_f: 250, cold_spring_percent: 50 }).cold_spring_gap_in - 0.78) < 1e-6);
  assert.strictEqual(_cv29p1({ material: "steel", run_length_ft: 100, install_temp_f: 70, operating_temp_f: 70 }).thermal_growth_in, 0);
  assert.ok("error" in _cv29p1({ material: "steel", run_length_ft: 0, install_temp_f: 50, operating_temp_f: 250 }));
  assert.ok("error" in _cv29p1({ material: "steel", run_length_ft: 100, install_temp_f: 50, operating_temp_f: 250, cold_spring_percent: 150 }));
  // raceway-expansion-fitting: 100 ft PVC dT 100 F -> 4.056 in, 1 fitting; length 0 rejected; below threshold -> not required
  assert.ok(Math.abs(_cv29p2({ run_length_ft: 100, temp_range_f: 100, fitting_travel_in: 6 }).length_change_in - 4.056) < 1e-6);
  assert.strictEqual(_cv29p2({ run_length_ft: 100, temp_range_f: 100, fitting_travel_in: 6 }).fittings_needed, 1);
  assert.strictEqual(_cv29p2({ run_length_ft: 1, temp_range_f: 1, fitting_travel_in: 6 }).requires_fitting, false);
  assert.ok("error" in _cv29p2({ run_length_ft: 0, temp_range_f: 100 }));
  // pipe-spacing-rack: 2.375 OD + 1 ins + 1 gap -> 5.375 c-c, 9.75 bundle; OD 0 rejected
  assert.strictEqual(_cv29p3({ pipe_od_in: 2.375, insulation_thickness_in: 1, clearance_in: 1, pipe_count: 2, rack_width_in: 24 }).center_to_center_in, 5.375);
  assert.strictEqual(_cv29p3({ pipe_od_in: 2.375, insulation_thickness_in: 1, clearance_in: 1, pipe_count: 2 }).total_bundle_width_in, 9.75);
  assert.ok("error" in _cv29p3({ pipe_od_in: 0, insulation_thickness_in: 1, clearance_in: 1 }));
});

// ---------------------------------------------------------------------------
// spec-v30 metal / air / refrigerant bench: groove-weld shear (AISC J2.5),
// total external static pressure (Manual D sum), refrigeration compression
// ratio (absolute pressures). Each pins its worked example and rejects
// non-finite / degenerate input.
// ---------------------------------------------------------------------------
import {
  computeGrooveWeldStrength as _cv30m1, computeDuctStaticTotal as _cv30m2, computeCompressionRatio as _cv30m3,
  computeGrooveWeldLengthForLoad as _v760,
} from "../../calc-metalair.js";

test("bounds: spec-v30 metal/air/refrigerant tiles pin constants + reject bad input", () => {
  // groove-weld: PJP throat 0.25, 6 in, E70, LRFD -> 47,250 lb; length 0 rejected; CJP needs base thickness
  assert.ok(Math.abs(_cv30m1({ weld_type: "PJP", effective_throat_in: 0.25, length_in: 6, electrode: "E70", method: "LRFD" }).capacity_lb - 47250) < 1e-3);
  assert.ok("error" in _cv30m1({ weld_type: "PJP", effective_throat_in: 0.25, length_in: 0, electrode: "E70" }));
  assert.ok("error" in _cv30m1({ weld_type: "CJP", base_thickness_in: 0, length_in: 6 }));
  // duct-static: 6 drops sum to 0.64; over 0.50 rating -> -0.14 remaining, not within; empty list rejected
  assert.ok(Math.abs(_cv30m2({ components: [{ drop_in_wc: 0.10 }, { drop_in_wc: 0.03 }, { drop_in_wc: 0.03 }, { drop_in_wc: 0.30 }, { drop_in_wc: 0.10 }, { drop_in_wc: 0.08 }], rated_esp_in_wc: 0.50 }).total_esp_in_wc - 0.64) < 1e-9);
  assert.strictEqual(_cv30m2({ components: [{ drop_in_wc: 0.64 }], rated_esp_in_wc: 0.50 }).within_rating, false);
  assert.ok("error" in _cv30m2({ components: [], rated_esp_in_wc: 0.5 }));
  assert.ok("error" in _cv30m2({ components: [{ drop_in_wc: -1 }], rated_esp_in_wc: 0.5 }));
  // compression-ratio: 70/260 psig at 14.696 -> 274.696/84.696 = 3.243; full-vacuum suction rejected; discharge < suction rejected
  assert.ok(Math.abs(_cv30m3({ suction_psig: 70, discharge_psig: 260, atmospheric_psia: 14.696 }).compression_ratio - 3.2433) < 1e-3);
  assert.ok("error" in _cv30m3({ suction_psig: -20, discharge_psig: 260, atmospheric_psia: 14.696 }));
  assert.ok("error" in _cv30m3({ suction_psig: 100, discharge_psig: 50, atmospheric_psia: 14.696 }));
});

test("bounds: spec-v760 groove weld length for an applied load (inverse of groove-weld-strength)", () => {
  const p = _v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.25, electrode: "E70", method: "LRFD" });
  assert.ok(Math.abs(p.required_length_in - 12.698) < 0.01);
  assert.ok(Math.abs(p.stress_ksi - 31.5) < 1e-9);
  // round-trip: the recovered length fed to groove-weld-strength reproduces the applied load as the capacity (util 1.0)
  for (const [load, type, throat, base, elec, method] of [[100000, "PJP", 0.25, 0, "E70", "LRFD"], [60000, "PJP", 0.3125, 0, "E80", "ASD"], [200000, "CJP", 0.5, 0.5, "E70", "LRFD"], [40000, "CJP", 0, 0.375, "E70", "ASD"]]) {
    const inv = _v760({ applied_load_lb: load, weld_type: type, effective_throat_in: throat, base_thickness_in: base, electrode: elec, method: method });
    const fwd = _cv30m1({ weld_type: type, effective_throat_in: throat, base_thickness_in: base, length_in: inv.required_length_in, electrode: elec, method: method, applied_load_lb: load });
    assert.ok(Math.abs(fwd.capacity_lb - load) < 1e-3);
    assert.ok(Math.abs(fwd.utilization - 1) < 1e-9);
  }
  // more load needs more length; a thicker throat needs less; LRFD (higher stress) needs less than ASD
  assert.ok(_v760({ applied_load_lb: 200000, weld_type: "PJP", effective_throat_in: 0.25 }).required_length_in > _v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.25 }).required_length_in);
  assert.ok(_v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.5 }).required_length_in < _v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.25 }).required_length_in);
  assert.ok(_v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.25, method: "LRFD" }).required_length_in < _v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0.25, method: "ASD" }).required_length_in);
  // error seams: non-positive load, missing throat for the weld type, non-finite
  assert.ok("error" in _v760({ applied_load_lb: 0, weld_type: "PJP", effective_throat_in: 0.25 }));
  assert.ok("error" in _v760({ applied_load_lb: 100000, weld_type: "PJP", effective_throat_in: 0 }));
  assert.ok("error" in _v760({ applied_load_lb: 100000, weld_type: "CJP", base_thickness_in: 0 }));
  assert.ok("error" in _v760({ applied_load_lb: Infinity, weld_type: "PJP", effective_throat_in: 0.25 }));
});

