  assert.ok("error" in _v652({ target_input_btuh: 100000, dial_size_cf: 0, heating_value_btu_cf: 1030 }));
  assert.ok("error" in _v652({ target_input_btuh: 100000, dial_size_cf: 1, heating_value_btu_cf: 0 }));
