  // Given time, solve the required intensity.
  const i = _v659({ target_dose_mj_cm2: 40, intensity_mw_cm2: 0, exposure_time_s: 8 });
  assert.ok(Math.abs(i.required_intensity_mw_cm2 - 5) < 1e-9 && i.required_time_s === null);
