import { computePvEnergyYield as _v221, computePvRowSpacing as _v222, computePvInverterRatio as _v223, computePvRowShadeAngle as _v702 } from "../../calc-solar.js";

test("bounds: spec-v221 computePvEnergyYield pins annual energy, specific yield, capacity factor, and error seams", () => {
  const r = _v221({ dc_kw: 8, psh: 5.0, perf_ratio: 0.77 });
  assert.strictEqual(r.annual_kwh, 11242);
  assert.ok(Math.abs(r.specific_yield - 1405.25) < 1e-9);
  assert.ok(Math.abs(r.capacity_factor - 0.16041666666666668) < 1e-9);
  assert.ok(Math.abs(r.monthly_kwh_avg - 11242 / 12) < 1e-9);
  const r2 = _v221({ dc_kw: 8, psh: 6.5, perf_ratio: 0.75 });
  assert.strictEqual(r2.annual_kwh, 14235);
  assert.ok(Math.abs(r2.specific_yield - 1779.375) < 1e-9);
  // Error seams.
  assert.ok("error" in _v221({ dc_kw: 0, psh: 5 }));
  assert.ok("error" in _v221({ dc_kw: 8, psh: 0 }));
  assert.ok("error" in _v221({ dc_kw: 8, psh: 5, perf_ratio: 0 }));
  assert.ok("error" in _v221({ dc_kw: 8, psh: 5, perf_ratio: 1.1 }));
  assert.ok("error" in _v221({ dc_kw: Infinity, psh: 5 }));
});

import { computePvArraySizing as _v647 } from "../../calc-solar.js";

test("bounds: spec-v647 computePvArraySizing inverts the PVWatts yield, round-trips it, scales inversely with PR, and pins error seams", () => {
  const r = _v647({ target_annual_kwh: 12000, psh: 5.0, perf_ratio: 0.77 });
  assert.ok(Math.abs(r.specific_yield - 1405.25) < 1e-9); // 5 x 365 x 0.77
  assert.ok(Math.abs(r.dc_kw - 12000 / 1405.25) < 1e-9);
  assert.ok(Math.abs(r.monthly_kwh_avg - 1000) < 1e-9);
  // Exact inverse of pv-energy-yield: the annual energy the sized array produces equals the target.
  assert.ok(Math.abs(_v221({ dc_kw: r.dc_kw, psh: 5.0, perf_ratio: 0.77 }).annual_kwh - 12000) < 1e-9);
  // Round-trip the energy tile's own desert example: 14235 kWh at 6.5 PSH, 0.75 PR sizes to exactly 8 kW.
  assert.ok(Math.abs(_v647({ target_annual_kwh: 14235, psh: 6.5, perf_ratio: 0.75 }).dc_kw - 8) < 1e-9);
  // A lower performance ratio needs a bigger array for the same target.
  assert.ok(_v647({ target_annual_kwh: 12000, psh: 5.0, perf_ratio: 0.70 }).dc_kw > r.dc_kw);
  // Error seams: non-positive target / psh, PR out of (0,1], non-finite.
  assert.ok("error" in _v647({ target_annual_kwh: 0, psh: 5, perf_ratio: 0.77 }));
  assert.ok("error" in _v647({ target_annual_kwh: 12000, psh: 0, perf_ratio: 0.77 }));
  assert.ok("error" in _v647({ target_annual_kwh: 12000, psh: 5, perf_ratio: 0 }));
  assert.ok("error" in _v647({ target_annual_kwh: 12000, psh: 5, perf_ratio: 1.1 }));
  assert.ok("error" in _v647({ target_annual_kwh: Infinity, psh: 5, perf_ratio: 0.77 }));
});

test("bounds: spec-v222 computePvRowSpacing pins pitch, GCR, the shallow-tilt case, and error seams", () => {
  const r = _v222({ module_length_ft: 6.5, tilt_deg: 30, profile_angle_deg: 22 });
  assert.ok(Math.abs(r.rise_ft - 3.25) < 1e-9);
  assert.ok(Math.abs(r.pitch_ft - 13.673197398) < 1e-6);
  assert.ok(Math.abs(r.gcr - 0.47538259) < 1e-6);
  const r2 = _v222({ module_length_ft: 6.5, tilt_deg: 10, profile_angle_deg: 22 });
  assert.ok(Math.abs(r2.pitch_ft - 9.194913485) < 1e-6);
  assert.ok(Math.abs(r2.gcr - 0.706912578) < 1e-6);
  // Error seams.
  assert.ok("error" in _v222({ module_length_ft: 0, tilt_deg: 30, profile_angle_deg: 22 }));
  assert.ok("error" in _v222({ module_length_ft: 6.5, tilt_deg: 91, profile_angle_deg: 22 }));
  assert.ok("error" in _v222({ module_length_ft: 6.5, tilt_deg: 30, profile_angle_deg: 0 }));
  assert.ok("error" in _v222({ module_length_ft: 6.5, tilt_deg: 30, profile_angle_deg: 91 }));
  assert.ok("error" in _v222({ module_length_ft: Infinity, tilt_deg: 30, profile_angle_deg: 22 }));
});

test("bounds: spec-v702 computePvRowShadeAngle pins prof = atan(rise/(pitch-base)), round-trips through computePvRowSpacing, and error seams", () => {
  const r = _v702({ module_length_ft: 6.5, tilt_deg: 30, row_pitch_ft: 12 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.profile_angle_deg - 27.02782059) < 1e-6, `profile angle: ${r.profile_angle_deg}`);
  assert.ok(Math.abs(r.gcr - 6.5 / 12) < 1e-9, `gcr: ${r.gcr}`);
  // Round-trip: the profile angle, fed back through the forward tile, reproduces the pitch.
  for (const module_length_ft of [4, 6.5, 10]) {
    for (const tilt_deg of [10, 30, 60]) {
      const base = module_length_ft * Math.cos(tilt_deg * Math.PI / 180);
      for (const row_pitch_ft of [base + 1, base + 6, base + 20]) {
        const m = _v702({ module_length_ft, tilt_deg, row_pitch_ft });
        assert.ok(!m.error, `sweep L=${module_length_ft} tilt=${tilt_deg} pitch=${row_pitch_ft}: ${JSON.stringify(m)}`);
        assertFinite(m.profile_angle_deg, "prof"); assert.ok(m.profile_angle_deg > 0 && m.profile_angle_deg < 90, "prof in (0,90)");
        const back = _v222({ module_length_ft, tilt_deg, profile_angle_deg: m.profile_angle_deg });
        assert.ok(Math.abs(back.pitch_ft - row_pitch_ft) < 1e-6, `round-trip L=${module_length_ft} tilt=${tilt_deg} pitch=${row_pitch_ft}: ${back.pitch_ft}`);
      }
    }
  }
  // More pitch means a lower (more forgiving) shade angle.
  assert.ok(_v702({ module_length_ft: 6.5, tilt_deg: 30, row_pitch_ft: 20 }).profile_angle_deg < r.profile_angle_deg);
  // Error seams: non-positive length, out-of-range tilt, pitch at/below the footprint, non-finite.
  assert.ok("error" in _v702({ module_length_ft: 0, tilt_deg: 30, row_pitch_ft: 12 }));
  assert.ok("error" in _v702({ module_length_ft: 6.5, tilt_deg: 0, row_pitch_ft: 12 }));
  assert.ok("error" in _v702({ module_length_ft: 6.5, tilt_deg: 91, row_pitch_ft: 12 }));
  assert.ok("error" in _v702({ module_length_ft: 6.5, tilt_deg: 30, row_pitch_ft: 5 }));
  assert.ok("error" in _v702({ module_length_ft: 6.5, tilt_deg: 30, row_pitch_ft: Infinity }));
});

test("bounds: spec-v223 computePvInverterRatio pins ILR, clipping onset, the three verdict bands, and error seams", () => {
  const r = _v223({ dc_kw: 8, ac_kw: 6.6, inv_eff: 0.96 });
  assert.ok(Math.abs(r.ilr - 1.212121212) < 1e-6);
  assert.ok(Math.abs(r.clip_dc_kw - 6.875) < 1e-9);
  assert.ok(Math.abs(r.clip_fraction - 0.859375) < 1e-9);
  assert.ok(/optimal/.test(r.verdict));
  // Undersized band.
  const r2 = _v223({ dc_kw: 10, ac_kw: 6.6 });
  assert.ok(Math.abs(r2.ilr - 1.515151515) < 1e-6);
  assert.ok(/undersized/.test(r2.verdict));
  // Oversized band.
  const r3 = _v223({ dc_kw: 6, ac_kw: 6.6 });
  assert.ok(/oversized/.test(r3.verdict));
  // Error seams.
  assert.ok("error" in _v223({ dc_kw: 0, ac_kw: 6.6 }));
  assert.ok("error" in _v223({ dc_kw: 8, ac_kw: 0 }));
  assert.ok("error" in _v223({ dc_kw: 8, ac_kw: 6.6, inv_eff: 0 }));
  assert.ok("error" in _v223({ dc_kw: 8, ac_kw: 6.6, inv_eff: 1.1 }));
  assert.ok("error" in _v223({ dc_kw: Infinity, ac_kw: 6.6 }));
});

