import { computeSoilConsolidationSettlement as _v308, computeFootingEccentricPressure as _v309, computeBoussinesqSurchargeWall as _v310 } from "../../calc-geotech.js";

test("bounds: spec-v308 computeSoilConsolidationSettlement pins the settlement, the log-ratio behavior, and error seams", () => {
  const r = _v308({ cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000, dsig_psf: 1000 });
  assert.ok(Math.abs(r.sc_in - 0.25 * 10 / 1.90 * Math.log10(3000 / 2000) * 12) < 1e-6);
  assert.ok(Math.abs(r.sc_in - 2.78) < 0.02);
  // Doubling the increment is NOT double the settlement (log of the ratio).
  const r2 = _v308({ cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000, dsig_psf: 2000 });
  assert.ok(r2.sc_in < 2 * r.sc_in);
  assert.ok(Math.abs(r2.sc_in - 4.75) < 0.02);
  // Error seams.
  assert.ok("error" in _v308({ cc: 0, h_ft: 10, e0: 0.9, sig0_psf: 2000, dsig_psf: 1000 }));
  assert.ok("error" in _v308({ cc: 0.25, h_ft: 0, e0: 0.9, sig0_psf: 2000, dsig_psf: 1000 }));
  assert.ok("error" in _v308({ cc: 0.25, h_ft: 10, e0: -1, sig0_psf: 2000, dsig_psf: 1000 }));
  assert.ok("error" in _v308({ cc: 0.25, h_ft: 10, e0: 0.9, sig0_psf: 0, dsig_psf: 1000 }));
  assert.ok("error" in _v308({ cc: Infinity, h_ft: 10, e0: 0.9, sig0_psf: 2000, dsig_psf: 1000 }));
});

import { computeSettlementLimitLoad as _v648 } from "../../calc-geotech.js";

test("bounds: spec-v648 computeSettlementLimitLoad inverts the consolidation settlement, round-trips it, holds the tighter-limit-less-load property, and pins error seams", () => {
  const r = _v648({ sc_allow_in: 2, cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000 });
  assert.ok(Math.abs(r.dsig_psf - 2000 * (Math.pow(10, (2 / 12) * 1.9 / (0.25 * 10)) - 1)) < 1e-6);
  assert.ok(Math.abs(r.dsig_psf - 677.3) < 0.5);
  assert.ok(Math.abs(r.final_stress_psf - (2000 + r.dsig_psf)) < 1e-9);
  // Exact inverse of the settlement tile: the settlement under the returned load is the allowable limit.
  assert.ok(Math.abs(_v308({ cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000, dsig_psf: r.dsig_psf }).sc_in - 2) < 1e-9);
  // Round-trip the settlement tile's own example: 2.7804 in -> 1000 psf.
  const scEx = _v308({ cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000, dsig_psf: 1000 }).sc_in;
  assert.ok(Math.abs(_v648({ sc_allow_in: scEx, cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000 }).dsig_psf - 1000) < 1e-6);
  // Log-ratio: halving the settlement limit allows far less than half the load.
  const tight = _v648({ sc_allow_in: 1, cc: 0.25, h_ft: 10, e0: 0.90, sig0_psf: 2000 });
  assert.ok(tight.dsig_psf < r.dsig_psf / 2);
  // Error seams: non-positive settlement / Cc / H / stress, non-finite.
  assert.ok("error" in _v648({ sc_allow_in: 0, cc: 0.25, h_ft: 10, e0: 0.9, sig0_psf: 2000 }));
  assert.ok("error" in _v648({ sc_allow_in: 2, cc: 0, h_ft: 10, e0: 0.9, sig0_psf: 2000 }));
  assert.ok("error" in _v648({ sc_allow_in: 2, cc: 0.25, h_ft: 0, e0: 0.9, sig0_psf: 2000 }));
  assert.ok("error" in _v648({ sc_allow_in: 2, cc: 0.25, h_ft: 10, e0: 0.9, sig0_psf: 0 }));
  assert.ok("error" in _v648({ sc_allow_in: Infinity, cc: 0.25, h_ft: 10, e0: 0.9, sig0_psf: 2000 }));
});

test("bounds: spec-v309 computeFootingEccentricPressure pins the kern branch flip, the outside-kern triangle, and error seams", () => {
  const r = _v309({ p_kip: 60, m_kft: 60, b_ft: 8, l_ft: 8 });
  assert.strictEqual(r.e_ft, 1);
  assert.ok(Math.abs(r.q_max_ksf - 60 / 64 * 1.75) < 1e-9);
  assert.ok(Math.abs(r.q_min_ksf - 60 / 64 * 0.25) < 1e-9);
  assert.ok(r.kern_status.startsWith("inside"));
  // Outside the kern: triangular bearing, q_min = 0, reduced length.
  const r2 = _v309({ p_kip: 60, m_kft: 120, b_ft: 8, l_ft: 8 });
  assert.strictEqual(r2.e_ft, 2);
  assert.strictEqual(r2.q_min_ksf, 0);
  assert.ok(Math.abs(r2.q_max_ksf - 2.5) < 1e-9);
  assert.ok(Math.abs(r2.bearing_len_ft - 6) < 1e-9);
  assert.ok(r2.kern_status.startsWith("outside"));
  // Exactly at e = B/6 the inside branch still applies (q_min = 0).
  const r3 = _v309({ p_kip: 60, m_kft: 80, b_ft: 8, l_ft: 8 }); // e = 1.333 = B/6
  assert.ok(r3.kern_status.startsWith("inside"));
  assert.ok(Math.abs(r3.q_min_ksf) < 1e-9);
  // Error seams.
  assert.ok("error" in _v309({ p_kip: 0, m_kft: 60, b_ft: 8, l_ft: 8 }));
  assert.ok("error" in _v309({ p_kip: 60, m_kft: 60, b_ft: 0, l_ft: 8 }));
  assert.ok("error" in _v309({ p_kip: 60, m_kft: 300, b_ft: 8, l_ft: 8 })); // e >= B/2 overturns
  assert.ok("error" in _v309({ p_kip: NaN, m_kft: 60, b_ft: 8, l_ft: 8 }));
});

test("bounds: spec-v310 computeBoussinesqSurchargeWall pins both branches, the setback behavior, and error seams", () => {
  const r = _v310({ ql_plf: 1000, h_ft: 10, x_ft: 4, z_ft: 3 });
  assert.ok(Math.abs(r.m_ratio - 0.4) < 1e-9);
  assert.ok(Math.abs(r.n_ratio - 0.3) < 1e-9);
  assert.ok(Math.abs(r.sigma_h_psf - 97.4) < 0.2); // m <= 0.4 branch
  // The two branches agree near m = 0.4 (continuity).
  const rEdge = _v310({ ql_plf: 1000, h_ft: 10, x_ft: 4.1, z_ft: 3 });
  assert.ok(Math.abs(rEdge.sigma_h_psf - r.sigma_h_psf) < 2);
  // A load set farther back pushes less.
  const r2 = _v310({ ql_plf: 1000, h_ft: 10, x_ft: 6, z_ft: 3 });
  assert.ok(r2.sigma_h_psf < r.sigma_h_psf);
  assert.ok(Math.abs(r2.sigma_h_psf - 68.3) < 0.2);
  // Error seams.
  assert.ok("error" in _v310({ ql_plf: 0, h_ft: 10, x_ft: 4, z_ft: 3 }));
  assert.ok("error" in _v310({ ql_plf: 1000, h_ft: 0, x_ft: 4, z_ft: 3 }));
  assert.ok("error" in _v310({ ql_plf: 1000, h_ft: 10, x_ft: 0, z_ft: 3 }));
  assert.ok("error" in _v310({ ql_plf: 1000, h_ft: 10, x_ft: 4, z_ft: 12 })); // z > H
  assert.ok("error" in _v310({ ql_plf: Infinity, h_ft: 10, x_ft: 4, z_ft: 3 }));
});

// ===================== spec-v311..v313 field-surveying depth batch =====================
import { computeDifferentialLeveling as _v311, computeStadiaDistance as _v312, computeTapingCorrections as _v313 } from "../../calc-survey.js";
import { computeCogoForwardPoint as _v766 } from "../../calc-survey.js";
import { computeEdmSlopeReduction as _v769 } from "../../calc-survey.js";
import { computeLevelingCurvatureRefraction as _v771 } from "../../calc-survey.js";
import { computeGridToGround as _v776 } from "../../calc-survey.js";
import { computeCogoInverseLocate as _v781 } from "../../calc-survey.js";

test("bounds: spec-v311 computeDifferentialLeveling pins the HI reduction, the sum identity, the misclosure, and error seams", () => {
  const r = _v311({ bm_elev: 100.00, bs: [4.32, 5.60], fs: [2.15, 3.40], known_close: 104.40 });
  assert.ok(Math.abs(r.final_elev - 104.37) < 1e-9);
  assert.ok(Math.abs(r.sum_bs - 9.92) < 1e-9);
  assert.ok(Math.abs(r.sum_fs - 5.55) < 1e-9);
  // The sum(BS) - sum(FS) identity equals the elevation change.
  assert.ok(Math.abs((r.sum_bs - r.sum_fs) - (r.final_elev - 100.00)) < 1e-9);
  assert.ok(Math.abs(r.misclosure - (-0.03)) < 1e-9);
  // Per-turning-point HI reduction.
  assert.ok(Math.abs(r.steps[0].hi - 104.32) < 1e-9);
  assert.ok(Math.abs(r.steps[0].elev - 102.17) < 1e-9);
  // No closing elevation -> null misclosure.
  assert.strictEqual(_v311({ bm_elev: 100, bs: [4.32, 5.60], fs: [2.15, 3.40] }).misclosure, null);
  // Error seams.
  assert.ok("error" in _v311({ bm_elev: 100, bs: [4.32], fs: [2.15, 3.40] })); // count mismatch
  assert.ok("error" in _v311({ bm_elev: 100, bs: [], fs: [] }));
  assert.ok("error" in _v311({ bm_elev: 100, bs: [4.32, NaN], fs: [2.15, 3.40] }));
  assert.ok("error" in _v311({ bm_elev: Infinity, bs: [4.32], fs: [2.15] }));
});

test("bounds: spec-v312 computeStadiaDistance pins the inclined case, the level-sight identity, and error seams", () => {
  const r = _v312({ s_ft: 1.50, theta_deg: 5, k_f: 100, hi_ft: 4.50, rod_ft: 5.20, sta_elev: 500.00 });
  const t = 5 * Math.PI / 180;
  assert.ok(Math.abs(r.h_ft - 100 * 1.5 * Math.cos(t) * Math.cos(t)) < 1e-9);
  assert.ok(Math.abs(r.v_ft - 100 * 1.5 * Math.cos(t) * Math.sin(t)) < 1e-9);
  assert.ok(Math.abs(r.elev_ft - (500 + 4.5 + r.v_ft - 5.2)) < 1e-9);
  assert.ok(Math.abs(r.h_ft - 148.86) < 0.02);
  // Level sight: H = K s, V = 0.
  const r2 = _v312({ s_ft: 1.50, theta_deg: 0, k_f: 100 });
  assert.ok(Math.abs(r2.h_ft - 150) < 1e-9);
  assert.ok(Math.abs(r2.v_ft) < 1e-12);
  assert.strictEqual(r2.elev_ft, null);
  // V uses sin(2 theta): equal magnitude, opposite sign for -theta.
  const rNeg = _v312({ s_ft: 1.50, theta_deg: -5, k_f: 100 });
  assert.ok(Math.abs(rNeg.v_ft + r.v_ft) < 1e-9);
  // Error seams.
  assert.ok("error" in _v312({ s_ft: 0, theta_deg: 5 }));
  assert.ok("error" in _v312({ s_ft: 1.5, theta_deg: 95 }));
  assert.ok("error" in _v312({ s_ft: 1.5, theta_deg: 5, k_f: 0 }));
  assert.ok("error" in _v312({ s_ft: Infinity, theta_deg: 5 }));
});

test("bounds: spec-v313 computeTapingCorrections pins the temp sign flip, the omitted-defaults-zero, and error seams", () => {
  const r = _v313({ l_ft: 100, t_f: 95, t0_f: 68, h_ft: 3 });
  assert.ok(Math.abs(r.ct_ft - 6.45e-6 * 27 * 100) < 1e-9);
  assert.ok(r.ct_ft > 0); // warm tape reads short, positive correction
  assert.ok(Math.abs(r.ch_ft - (-9 / 200)) < 1e-9);
  assert.strictEqual(r.cp_ft, 0); // omitted tension
  assert.strictEqual(r.cs_ft, 0); // omitted sag
  assert.ok(Math.abs(r.corrected_ft - 99.972) < 1e-3);
  // Cold tape flips the temperature sign.
  const r2 = _v313({ l_ft: 100, t_f: 40, t0_f: 68, h_ft: 0 });
  assert.ok(r2.ct_ft < 0);
  assert.strictEqual(r2.ch_ft, 0); // omitted slope
  assert.ok(Math.abs(r2.corrected_ft - 99.982) < 1e-3);
  // A tension correction when A and P are provided.
  const r3 = _v313({ l_ft: 100, t_f: 68, t0_f: 68, p_lb: 20, p0_lb: 10, a_in2: 0.005 });
  assert.ok(r3.cp_ft > 0);
  // Error seams.
  assert.ok("error" in _v313({ l_ft: 0 }));
  assert.ok("error" in _v313({ l_ft: 100, w_plf: 1.5, p_lb: 0 })); // sag needs positive pull
  assert.ok("error" in _v313({ l_ft: Infinity }));
});

test("bounds: spec-v766 cogo-forward-point pins latitude/departure, the cardinal directions, closure round-trip, and error seams", () => {
  // Spec example: N5000/E5000, azimuth 45, 200 ft -> dN = dE = 141.421; N2 = E2 = 5141.421.
  const r = _v766({ start_n: 5000, start_e: 5000, azimuth_deg: 45, distance_ft: 200 });
  assert.ok(Math.abs(r.delta_n - 200 * Math.cos(Math.PI / 4)) < 1e-9);
  assert.ok(Math.abs(r.delta_e - 200 * Math.sin(Math.PI / 4)) < 1e-9);
  assert.ok(Math.abs(r.delta_n - 141.42136) < 1e-4 && Math.abs(r.delta_e - 141.42136) < 1e-4);
  assert.ok(Math.abs(r.end_n - 5141.42136) < 1e-4 && Math.abs(r.end_e - 5141.42136) < 1e-4);
  // Cardinal azimuths: due north puts all distance in +dN, east in +dE, south -dN, west -dE.
  const north = _v766({ start_n: 0, start_e: 0, azimuth_deg: 0, distance_ft: 100 });
  assert.ok(Math.abs(north.delta_n - 100) < 1e-9 && Math.abs(north.delta_e) < 1e-9);
  const east = _v766({ start_n: 0, start_e: 0, azimuth_deg: 90, distance_ft: 100 });
  assert.ok(Math.abs(east.delta_e - 100) < 1e-9 && Math.abs(east.delta_n) < 1e-9);
  const south = _v766({ start_n: 0, start_e: 0, azimuth_deg: 180, distance_ft: 100 });
  assert.ok(Math.abs(south.delta_n + 100) < 1e-9);
  const west = _v766({ start_n: 0, start_e: 0, azimuth_deg: 270, distance_ft: 100 });
  assert.ok(Math.abs(west.delta_e + 100) < 1e-9);
  // Round-trip: locate forward, then the reverse azimuth over the same distance returns to the start.
  for (let i = 0; i < 200; i++) {
    const az = (i * 1.7) % 360;
    const d = 10 + (i % 40) * 25;
    const n0 = 1000 + i * 3, e0 = 2000 - i * 2;
    const out = _v766({ start_n: n0, start_e: e0, azimuth_deg: az, distance_ft: d });
    assert.ok(!out.error, JSON.stringify({ az, d }));
    const back = _v766({ start_n: out.end_n, start_e: out.end_e, azimuth_deg: (az + 180) % 360, distance_ft: d });
    assert.ok(Math.abs(back.end_n - n0) < 1e-6 && Math.abs(back.end_e - e0) < 1e-6, "reverse azimuth returns to start");
    // Distance identity: the leg length equals sqrt(dN^2 + dE^2).
    assert.ok(Math.abs(Math.hypot(out.delta_n, out.delta_e) - d) < 1e-6, "leg length = distance");
  }
  // Error seams.
  assert.ok("error" in _v766({ start_n: 0, start_e: 0, azimuth_deg: 45, distance_ft: 0 }));
  assert.ok("error" in _v766({ start_n: 0, start_e: 0, azimuth_deg: -5, distance_ft: 100 }));
  assert.ok("error" in _v766({ start_n: 0, start_e: 0, azimuth_deg: 361, distance_ft: 100 }));
  assert.ok("error" in _v766({ start_n: 0, start_e: 0, azimuth_deg: 45, distance_ft: Infinity }));
  assert.ok("error" in _v766({ start_n: NaN, start_e: 0, azimuth_deg: 45, distance_ft: 100 }));
});

test("bounds: spec-v769 edm-slope-reduction pins H = S sinZ / V = S cosZ, zenith/vertical equivalence, HI/HR, Pythagoras, and error seams", () => {
  // Spec example: S 250, zenith 86 -> H = 250 sin86 = 249.391, V = 250 cos86 = 17.439.
  const r = _v769({ angle_mode: "zenith", slope_distance_ft: 250, angle_deg: 86 });
  assert.ok(Math.abs(r.horizontal_ft - 250 * Math.sin(86 * Math.PI / 180)) < 1e-9);
  assert.ok(Math.abs(r.horizontal_ft - 249.391) < 1e-3);
  assert.ok(Math.abs(r.vertical_ft - 250 * Math.cos(86 * Math.PI / 180)) < 1e-9);
  assert.ok(Math.abs(r.vertical_ft - 17.439) < 1e-3);
  assert.ok(Math.abs(r.elev_diff_ft - r.vertical_ft) < 1e-12, "no HI/HR -> elev diff = V");
  // Zenith Z and vertical angle a = 90 - Z give identical H and V.
  for (let i = 0; i < 150; i++) {
    const S = 20 + i * 3;
    const Z = 60 + (i % 60);                 // zenith 60..119 deg
    const a = 90 - Z;                         // matching vertical angle
    const zr = _v769({ angle_mode: "zenith", slope_distance_ft: S, angle_deg: Z });
    const vr = _v769({ angle_mode: "vertical", slope_distance_ft: S, angle_deg: a });
    assert.ok(!zr.error && !vr.error, JSON.stringify({ S, Z, a }));
    assert.ok(Math.abs(zr.horizontal_ft - vr.horizontal_ft) < 1e-9, "zenith/vertical H agree");
    assert.ok(Math.abs(zr.vertical_ft - vr.vertical_ft) < 1e-9, "zenith/vertical V agree");
    // Pythagoras: H^2 + V^2 = S^2.
    assert.ok(Math.abs(Math.hypot(zr.horizontal_ft, zr.vertical_ft) - S) < 1e-6, "H^2 + V^2 = S^2");
    // Horizontal distance never exceeds the slope distance.
    assert.ok(zr.horizontal_ft <= S + 1e-9);
  }
  // Level shot (zenith 90): all horizontal, zero rise.
  const level = _v769({ angle_mode: "zenith", slope_distance_ft: 100, angle_deg: 90 });
  assert.ok(Math.abs(level.horizontal_ft - 100) < 1e-9 && Math.abs(level.vertical_ft) < 1e-9);
  // HI/HR shift the elevation difference by (HI - HR).
  const withHt = _v769({ angle_mode: "zenith", slope_distance_ft: 250, angle_deg: 86, hi_ft: 5.2, hr_ft: 6.0 });
  assert.ok(Math.abs(withHt.elev_diff_ft - (r.vertical_ft + 5.2 - 6.0)) < 1e-9);
  // Error seams.
  assert.ok("error" in _v769({ angle_mode: "zenith", slope_distance_ft: 0, angle_deg: 86 }));
  assert.ok("error" in _v769({ angle_mode: "zenith", slope_distance_ft: 250, angle_deg: 0 }));
  assert.ok("error" in _v769({ angle_mode: "zenith", slope_distance_ft: 250, angle_deg: 180 }));
  assert.ok("error" in _v769({ angle_mode: "vertical", slope_distance_ft: 250, angle_deg: 90 }));
  assert.ok("error" in _v769({ angle_mode: "sideways", slope_distance_ft: 250, angle_deg: 45 }));
  assert.ok("error" in _v769({ angle_mode: "zenith", slope_distance_ft: Infinity, angle_deg: 86 }));
});

test("bounds: spec-v771 leveling-curvature-refraction pins h_cr = 0.0206 K^2, component split, quadratic scaling, and error seams", () => {
  // Spec example: 2000 ft -> K = 2 -> correction = 0.0206*4 = 0.0824 ft.
  const r = _v771({ sight_distance_ft: 2000 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.correction_ft - 0.0824) < 1e-6);
  assert.ok(Math.abs(r.curvature_ft - 0.0239 * 4) < 1e-9);
  assert.ok(Math.abs(r.refraction_ft - 0.0033 * 4) < 1e-9);
  // The combined correction is exactly curvature minus refraction.
  assert.ok(Math.abs(r.correction_ft - (r.curvature_ft - r.refraction_ft)) < 1e-12);
  // Cross-check the mile form: 1 mile = 5280 ft -> 0.574 M^2 with M=1 -> 0.574 ft.
  const mile = _v771({ sight_distance_ft: 5280 });
  assert.ok(Math.abs(mile.correction_ft - 0.574) < 1e-3, "mile form: " + mile.correction_ft);
  // Quadratic in distance: double the sight -> 4x the correction.
  for (let i = 1; i <= 40; i++) {
    const d = i * 150;
    const a = _v771({ sight_distance_ft: d });
    const b = _v771({ sight_distance_ft: 2 * d });
    assert.ok(!a.error && !b.error);
    assert.ok(Math.abs(b.correction_ft / a.correction_ft - 4) < 1e-9, "quadratic scaling");
    assert.ok(a.correction_ft > 0 && a.curvature_ft > a.refraction_ft, "curvature dominates");
  }
  // Error seams.
  assert.ok("error" in _v771({ sight_distance_ft: 0 }));
  assert.ok("error" in _v771({ sight_distance_ft: -100 }));
  assert.ok("error" in _v771({ sight_distance_ft: Infinity }));
  assert.ok("error" in _v771({ sight_distance_ft: NaN }));
});

test("bounds: spec-v776 grid-to-ground pins EF = R/(R+h), CF = GSF*EF, ground = grid/CF, reverse, and error seams", () => {
  const R = 20906000;
  // Spec example: GSF 0.9999, h 5280, grid 10000 -> EF 0.9997475, CF 0.9996475, ground 10003.53.
  const r = _v776({ grid_distance_ft: 10000, grid_scale_factor: 0.9999, ellipsoid_height_ft: 5280 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.elevation_factor - R / (R + 5280)) < 1e-12);
  assert.ok(Math.abs(r.combined_factor - 0.9999 * (R / (R + 5280))) < 1e-12);
  assert.ok(Math.abs(r.ground_distance_ft - 10000 / r.combined_factor) < 1e-9);
  assert.ok(Math.abs(r.ground_distance_ft - 10003.53) < 0.02);
  // At sea level (h=0) the elevation factor is exactly 1; ground = grid / GSF.
  const sea = _v776({ grid_distance_ft: 10000, grid_scale_factor: 0.9999, ellipsoid_height_ft: 0 });
  assert.ok(Math.abs(sea.elevation_factor - 1) < 1e-12);
  assert.ok(Math.abs(sea.ground_distance_ft - 10000 / 0.9999) < 1e-9);
  // Above the ellipsoid the ground exceeds the grid (CF < 1 when GSF and EF < 1).
  assert.ok(r.ground_distance_ft > 10000, "ground > grid above the ellipsoid");
  // Round-trip and scalings across a sweep; ground = grid / CF exactly, linear in grid distance.
  for (let i = 0; i < 200; i++) {
    const grid = 100 + i * 137;
    const gsf = 0.9996 + (i % 9) * 0.0001;
    const h = -500 + (i % 40) * 300;
    const m = _v776({ grid_distance_ft: grid, grid_scale_factor: gsf, ellipsoid_height_ft: h });
    assert.ok(!m.error, JSON.stringify({ grid, gsf, h }));
    const cf = gsf * (R / (R + h));
    assert.ok(Math.abs(m.combined_factor - cf) < 1e-12, "CF identity");
    assert.ok(Math.abs(m.ground_distance_ft - grid / cf) < 1e-6, "ground = grid/CF");
    // Reverse: ground x CF returns the grid distance.
    assert.ok(Math.abs(m.ground_distance_ft * m.combined_factor - grid) < 1e-6, "reverse grid = ground x CF");
    // Linear in grid distance.
    const dbl = _v776({ grid_distance_ft: 2 * grid, grid_scale_factor: gsf, ellipsoid_height_ft: h });
    assert.ok(Math.abs(dbl.ground_distance_ft - 2 * m.ground_distance_ft) < 1e-6, "linear in grid");
  }
  // Error seams.
  assert.ok("error" in _v776({ grid_distance_ft: 0, grid_scale_factor: 0.9999, ellipsoid_height_ft: 5280 }));
  assert.ok("error" in _v776({ grid_distance_ft: 10000, grid_scale_factor: 0, ellipsoid_height_ft: 5280 }));
  assert.ok("error" in _v776({ grid_distance_ft: 10000, grid_scale_factor: 0.9999, ellipsoid_height_ft: NaN }));
  assert.ok("error" in _v776({ grid_distance_ft: Infinity, grid_scale_factor: 0.9999, ellipsoid_height_ft: 5280 }));
});

test("bounds: spec-v781 cogo-inverse-locate pins distance/azimuth, the cardinal directions, the forward round-trip, and error seams", () => {
  // Spec example: N5000/E5000 -> N5141.42/E5141.42 -> 200 ft at azimuth 45 deg.
  const r = _v781({ start_n: 5000, start_e: 5000, end_n: 5141.42, end_e: 5141.42 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.distance_ft - Math.hypot(141.42, 141.42)) < 1e-9);
  assert.ok(Math.abs(r.distance_ft - 200) < 0.01);
  assert.ok(Math.abs(r.azimuth_deg - 45) < 1e-3);
  // Cardinal directions: due north az 0, east 90, south 180, west 270.
  assert.ok(Math.abs(_v781({ start_n: 0, start_e: 0, end_n: 100, end_e: 0 }).azimuth_deg - 0) < 1e-9);
  assert.ok(Math.abs(_v781({ start_n: 0, start_e: 0, end_n: 0, end_e: 100 }).azimuth_deg - 90) < 1e-9);
  assert.ok(Math.abs(_v781({ start_n: 0, start_e: 0, end_n: -100, end_e: 0 }).azimuth_deg - 180) < 1e-9);
  assert.ok(Math.abs(_v781({ start_n: 0, start_e: 0, end_n: 0, end_e: -100 }).azimuth_deg - 270) < 1e-9);
  // Round-trip against the forward tile: inverse -> forward reproduces the end point.
  for (let i = 0; i < 250; i++) {
    const n1 = 1000 + i * 3, e1 = 2000 - i * 2;
    const n2 = n1 + (((i * 7) % 200) - 100) + 0.5, e2 = e1 + (((i * 11) % 200) - 100) + 0.5;
    const inv = _v781({ start_n: n1, start_e: e1, end_n: n2, end_e: e2 });
    if (inv.error) continue; // identical points skipped
    assert.ok(Math.abs(inv.distance_ft - Math.hypot(n2 - n1, e2 - e1)) < 1e-9, "distance identity");
    assert.ok(inv.azimuth_deg >= 0 && inv.azimuth_deg < 360, "azimuth normalized");
    const fwd = _v766({ start_n: n1, start_e: e1, azimuth_deg: inv.azimuth_deg, distance_ft: inv.distance_ft });
    assert.ok(!fwd.error, JSON.stringify({ n1, e1, inv }));
    assert.ok(Math.abs(fwd.end_n - n2) < 1e-6 && Math.abs(fwd.end_e - e2) < 1e-6, "inverse->forward returns the end point");
  }
  // Error seams.
  assert.ok("error" in _v781({ start_n: 5000, start_e: 5000, end_n: 5000, end_e: 5000 }), "identical points rejected");
  assert.ok("error" in _v781({ start_n: NaN, start_e: 5000, end_n: 5100, end_e: 5100 }));
  assert.ok("error" in _v781({ start_n: 5000, start_e: 5000, end_n: Infinity, end_e: 5100 }));
});

// ===================== spec-v314..v316 steel beam-column-and-connection depth batch =====================
import { computeSteelH1Interaction as _v314, computeSteelEffectiveLengthK as _v315, computeSteelBoltTensionShear as _v316 } from "../../calc-steel.js";

test("bounds: spec-v314 computeSteelH1Interaction pins both branches, the biaxial term, and error seams", () => {
  const r = _v314({ pr_kip: 100, pc_kip: 400, mrx_kft: 80, mcx_kft: 200 });
  assert.ok(Math.abs(r.ratio - 0.25) < 1e-9);
  assert.ok(Math.abs(r.interaction - (0.25 + 8 / 9 * 0.4)) < 1e-9);
  assert.strictEqual(r.pass, true);
  assert.ok(r.branch.startsWith("high-axial"));
  // Low-axial branch below Pr/Pc = 0.2.
  const r2 = _v314({ pr_kip: 50, pc_kip: 400, mrx_kft: 80, mcx_kft: 200 });
  assert.ok(Math.abs(r2.interaction - (0.125 / 2 + 0.4)) < 1e-9);
  assert.ok(r2.branch.startsWith("low-axial"));
  // The biaxial term adds the weak-axis ratio.
  const r3 = _v314({ pr_kip: 100, pc_kip: 400, mrx_kft: 80, mcx_kft: 200, mry_kft: 30, mcy_kft: 100 });
  assert.ok(Math.abs(r3.interaction - (0.25 + 8 / 9 * (0.4 + 0.3))) < 1e-9);
  // Error seams.
  assert.ok("error" in _v314({ pr_kip: 100, pc_kip: 0, mrx_kft: 80, mcx_kft: 200 }));
  assert.ok("error" in _v314({ pr_kip: 100, pc_kip: 400, mrx_kft: 80, mcx_kft: 0 }));
  assert.ok("error" in _v314({ pr_kip: 100, pc_kip: 400, mrx_kft: 80, mcx_kft: 200, mry_kft: 30, mcy_kft: 0 }));
  assert.ok("error" in _v314({ pr_kip: Infinity, pc_kip: 400, mrx_kft: 80, mcx_kft: 200 }));
});

test("bounds: spec-v315 computeSteelEffectiveLengthK pins sway vs braced, the fixed-limit trend, and error seams", () => {
  const s = _v315({ ga: 1, gb: 2, frame: "sway" });
  assert.ok(Math.abs(s.k_factor - 1.47) < 0.01);
  const b = _v315({ ga: 1, gb: 2, frame: "braced" });
  assert.ok(Math.abs(b.k_factor - 0.82) < 0.01);
  // A sway frame gives a larger K than braced for the same joints.
  assert.ok(s.k_factor > b.k_factor);
  // Stiffer joints trend toward the fixed limits (sway -> 1.0, braced -> 0.5).
  const s2 = _v315({ ga: 1, gb: 1, frame: "sway" });
  assert.ok(s2.k_factor < s.k_factor);
  const bStiff = _v315({ ga: 0.1, gb: 0.1, frame: "braced" });
  assert.ok(bStiff.k_factor < 0.6); // approaching 0.5
  // Error seams.
  assert.ok("error" in _v315({ ga: 0, gb: 2, frame: "sway" }));
  assert.ok("error" in _v315({ ga: 1, gb: 0, frame: "sway" }));
  assert.ok("error" in _v315({ ga: 1, gb: 2, frame: "bogus" }));
  assert.ok("error" in _v315({ ga: NaN, gb: 2, frame: "sway" }));
});

test("bounds: spec-v316 computeSteelBoltTensionShear pins the reduction, the cap and floor, the ASD branch, and error seams", () => {
  const r = _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 20, method: "LRFD" });
  assert.ok(Math.abs(r.fpnt_ksi - (1.3 * 90 - 90 / (0.75 * 54) * 20)) < 1e-9);
  assert.ok(Math.abs(r.fpnt_ksi - 72.6) < 0.1);
  assert.ok(Math.abs(r.avail_tension_kip - 0.75 * r.fpnt_ksi * 0.442) < 1e-9);
  // No shear: F'nt caps at Fnt.
  const r2 = _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 0, method: "LRFD" });
  assert.strictEqual(r2.fpnt_ksi, 90);
  assert.ok(Math.abs(r2.avail_tension_kip - 0.75 * 90 * 0.442) < 1e-9);
  // Full shear floors F'nt at zero.
  const r3 = _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 54, method: "LRFD" });
  assert.strictEqual(r3.fpnt_ksi, 0);
  // ASD branch uses Omega = 2.00.
  const rA = _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 10, method: "ASD" });
  assert.ok(Math.abs(rA.fpnt_ksi - Math.min(1.3 * 90 - 2 * 90 / 54 * 10, 90)) < 1e-9);
  // Error seams.
  assert.ok("error" in _v316({ fnt_ksi: 0, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 20 }));
  assert.ok("error" in _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0, frv_ksi: 20 }));
  assert.ok("error" in _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 20, method: "bogus" }));
  assert.ok("error" in _v316({ fnt_ksi: 90, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: -1 }));
  assert.ok("error" in _v316({ fnt_ksi: Infinity, fnv_ksi: 54, ab_in2: 0.442, frv_ksi: 20 }));
});

// ===================== spec-v317..v319 machining depth batch =====================
import { computeRadialChipThinning as _v317, computeBoringBarDeflection as _v318, computeBallnoseScallopHeight as _v319, computeBoringBarMaxOverhang as _v682 } from "../../calc-machining.js";

test("bounds: spec-v317 computeRadialChipThinning pins the thinning factor, the half-immersion crossover, and error seams", () => {
  const r = _v317({ ae_in: 0.05, d_in: 0.5, fz_target: 0.004 });
  assert.ok(Math.abs(r.rctf - 1 / (2 * Math.sqrt(0.1 - 0.01))) < 1e-9);
  assert.ok(Math.abs(r.rctf - 1.6667) < 1e-3);
  assert.ok(Math.abs(r.fz_prog - 0.004 * r.rctf) < 1e-12);
  // Quarter engagement is a milder bump.
  assert.ok(Math.abs(_v317({ ae_in: 0.125, d_in: 0.5, fz_target: 0.004 }).rctf - 1.1547) < 1e-3);
  // Half immersion: exactly 1.0, no thinning.
  assert.strictEqual(_v317({ ae_in: 0.25, d_in: 0.5, fz_target: 0.004 }).rctf, 1.0);
  // A full slot (ae >= D) also pins RCTF = 1.0.
  assert.strictEqual(_v317({ ae_in: 0.5, d_in: 0.5, fz_target: 0.004 }).rctf, 1.0);
  // Error seams.
  assert.ok("error" in _v317({ ae_in: 0.05, d_in: 0, fz_target: 0.004 }));
  assert.ok("error" in _v317({ ae_in: 0, d_in: 0.5, fz_target: 0.004 }));
  assert.ok("error" in _v317({ ae_in: Infinity, d_in: 0.5, fz_target: 0.004 }));
});

test("bounds: spec-v318 computeBoringBarDeflection pins the cantilever, the L^3 scaling, the L/d verdict, and error seams", () => {
  const r = _v318({ d_in: 0.75, l_in: 6, f_lb: 100, e_psi: 30e6 });
  assert.ok(Math.abs(r.i_in4 - Math.PI * Math.pow(0.75, 4) / 64) < 1e-12);
  assert.ok(Math.abs(r.delta_in - 0.01546) < 1e-4);
  assert.strictEqual(r.ld, 8);
  assert.ok(r.verdict.includes("carbide")); // L/d = 8 is the top of the carbide band
  // Past 8 is chatter-prone.
  assert.ok(_v318({ d_in: 0.5, l_in: 6, f_lb: 100, e_psi: 30e6 }).verdict.includes("chatter-prone")); // L/d = 12
  // Halving the overhang cuts the deflection to one-eighth (L^3).
  const r2 = _v318({ d_in: 0.75, l_in: 3, f_lb: 100, e_psi: 30e6 });
  assert.ok(Math.abs(r2.delta_in - r.delta_in / 8) < 1e-9);
  assert.strictEqual(r2.ld, 4);
  assert.ok(r2.verdict.includes("stable"));
  // A stiffer carbide bar (higher E) deflects less.
  assert.ok(_v318({ d_in: 0.75, l_in: 6, f_lb: 100, e_psi: 90e6 }).delta_in < r.delta_in);
  // Error seams.
  assert.ok("error" in _v318({ d_in: 0, l_in: 6, f_lb: 100 }));
  assert.ok("error" in _v318({ d_in: 0.75, l_in: 0, f_lb: 100 }));
  assert.ok("error" in _v318({ d_in: 0.75, l_in: 6, f_lb: 0 }));
  assert.ok("error" in _v318({ d_in: 0.75, l_in: 6, f_lb: 100, e_psi: 0 }));
  assert.ok("error" in _v318({ d_in: NaN, l_in: 6, f_lb: 100 }));
});

test("bounds: spec-v682 computeBoringBarMaxOverhang pins L_max = (3 E I delta / F)^(1/3), round-trips through computeBoringBarDeflection, and error seams", () => {
  const fwd = _v318({ d_in: 0.75, l_in: 6, f_lb: 100, e_psi: 30e6 });
  const r = _v682({ d_in: 0.75, f_lb: 100, allowable_deflection_in: fwd.delta_in, e_psi: 30e6 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.max_overhang_in - 6) < 1e-6, `L_max identity: ${r.max_overhang_in}`);
  assert.ok(Math.abs(r.ld - 8) < 1e-6, `L/d at max: ${r.ld}`);
  // A stiffer carbide bar can stick out farther for the same deflection.
  const carbide = _v682({ d_in: 0.75, f_lb: 100, allowable_deflection_in: fwd.delta_in, e_psi: 90e6 });
  assert.ok(carbide.max_overhang_in > r.max_overhang_in, `carbide farther: ${carbide.max_overhang_in}`);
  // Round-trip: the max overhang, fed back through the forward tile, reproduces the allowable deflection.
  for (const d_in of [0.5, 0.75, 1.0]) {
    for (const allowable_deflection_in of [0.002, 0.01, 0.03]) {
      const m = _v682({ d_in, f_lb: 100, allowable_deflection_in, e_psi: 30e6 });
      assert.ok(!m.error, `sweep d=${d_in} delta=${allowable_deflection_in}: ${JSON.stringify(m)}`);
      assertFinite(m.max_overhang_in, "L"); assert.ok(m.max_overhang_in > 0, "L positive");
      const back = _v318({ d_in, l_in: m.max_overhang_in, f_lb: 100, e_psi: 30e6 });
      assert.ok(Math.abs(back.delta_in - allowable_deflection_in) < 1e-9, `round-trip d=${d_in} delta=${allowable_deflection_in}: ${back.delta_in}`);
    }
  }
  // Error seams: non-positive diameter / force / allowable deflection / modulus, non-finite.
  assert.ok("error" in _v682({ d_in: 0, f_lb: 100, allowable_deflection_in: 0.01 }));
  assert.ok("error" in _v682({ d_in: 0.75, f_lb: 0, allowable_deflection_in: 0.01 }));
  assert.ok("error" in _v682({ d_in: 0.75, f_lb: 100, allowable_deflection_in: 0 }));
  assert.ok("error" in _v682({ d_in: 0.75, f_lb: 100, allowable_deflection_in: 0.01, e_psi: 0 }));
  assert.ok("error" in _v682({ d_in: NaN, f_lb: 100, allowable_deflection_in: 0.01 }));
});

test("bounds: spec-v319 computeBallnoseScallopHeight pins the forward/inverse round-trip, the s^2 scaling, and error seams", () => {
  const r = _v319({ r_in: 0.25, mode: "scallop-from-stepover", s_in: 0.030 });
  assert.ok(Math.abs(r.out_in - (0.25 - Math.sqrt(0.0625 - 0.000225))) < 1e-9);
  assert.ok(Math.abs(r.out_in - 0.00045) < 5e-6);
  // Double the stepover -> ~4x the scallop (s^2 law).
  const r2 = _v319({ r_in: 0.25, mode: "scallop-from-stepover", s_in: 0.060 });
  assert.ok(Math.abs(r2.out_in / r.out_in - 4) < 0.05);
  // The inverse round-trips: target scallop returns the stepover.
  const rInv = _v319({ r_in: 0.25, mode: "stepover-from-scallop", h_in: r.out_in });
  assert.ok(Math.abs(rInv.out_in - 0.030) < 1e-6);
  // Error seams.
  assert.ok("error" in _v319({ r_in: 0, mode: "scallop-from-stepover", s_in: 0.03 }));
  assert.ok("error" in _v319({ r_in: 0.25, mode: "scallop-from-stepover", s_in: 0.6 })); // s > 2R
  assert.ok("error" in _v319({ r_in: 0.25, mode: "stepover-from-scallop", h_in: 0.3 })); // h >= R
  assert.ok("error" in _v319({ r_in: 0.25, mode: "bogus", s_in: 0.03 }));
  assert.ok("error" in _v319({ r_in: NaN, mode: "scallop-from-stepover", s_in: 0.03 }));
});

// ===================== spec-v320..v322 refrigeration-cycle batch =====================
import { computeRefrigerantMassFlow as _v320, computeRefrigerationCop as _v321, computeCondenserHeatRejection as _v322 } from "../../calc-refrigerant.js";

test("bounds: spec-v320 computeRefrigerantMassFlow pins the tons path, the inverse-RE scaling, and error seams", () => {
  const r = _v320({ q: 5, unit_tons: 1, h1_btulb: 180, h4_btulb: 120 });
  assert.strictEqual(r.re_btulb, 60);
  assert.ok(Math.abs(r.m_dot_lbmin - 1000 / 60) < 1e-9);
  assert.ok(Math.abs(r.m_dot_lbh - r.m_dot_lbmin * 60) < 1e-9);
  // A smaller refrigeration effect raises the mass flow (1/RE).
  const r2 = _v320({ q: 5, unit_tons: 1, h1_btulb: 180, h4_btulb: 130 });
  assert.ok(Math.abs(r2.m_dot_lbmin - 20) < 1e-9);
  assert.ok(r2.m_dot_lbmin > r.m_dot_lbmin);
  // Btu/h unit path.
  assert.ok(Math.abs(_v320({ q: 60000, unit_tons: 0, h1_btulb: 180, h4_btulb: 120 }).m_dot_lbmin - 1000 / 60) < 1e-9);
  // Error seams.
  assert.ok("error" in _v320({ q: 0, h1_btulb: 180, h4_btulb: 120 }));
  assert.ok("error" in _v320({ q: 5, unit_tons: 1, h1_btulb: 120, h4_btulb: 180 })); // h1 <= h4
  assert.ok("error" in _v320({ q: Infinity, h1_btulb: 180, h4_btulb: 120 }));
});

test("bounds: spec-v321 computeRefrigerationCop pins the COP, the Carnot Rankine conversion, the EER identity, and error seams", () => {
  const r = _v321({ h1_btulb: 180, h2_btulb: 205, h4_btulb: 120, tevap_f: 40, tcond_f: 120 });
  assert.ok(Math.abs(r.cop - 60 / 25) < 1e-9);
  assert.ok(Math.abs(r.eer - 3.412 * r.cop) < 1e-9);
  assert.ok(Math.abs(r.cop_carnot - 499.67 / 80) < 1e-9);
  assert.ok(Math.abs(r.eta_2nd - r.cop / r.cop_carnot) < 1e-12);
  // A smaller lift raises the Carnot ceiling.
  const r2 = _v321({ h1_btulb: 180, h2_btulb: 205, h4_btulb: 120, tevap_f: 45, tcond_f: 120 });
  assert.ok(r2.cop_carnot > r.cop_carnot);
  assert.ok(Math.abs(r2.cop_carnot - 504.67 / 75) < 1e-9);
  // Error seams.
  assert.ok("error" in _v321({ h1_btulb: 180, h2_btulb: 180, h4_btulb: 120, tevap_f: 40, tcond_f: 120 })); // h2 <= h1
  assert.ok("error" in _v321({ h1_btulb: 120, h2_btulb: 205, h4_btulb: 180, tevap_f: 40, tcond_f: 120 })); // h1 <= h4
  assert.ok("error" in _v321({ h1_btulb: 180, h2_btulb: 205, h4_btulb: 120, tevap_f: 120, tcond_f: 40 })); // Tcond <= Tevap
  assert.ok("error" in _v321({ h1_btulb: Infinity, h2_btulb: 205, h4_btulb: 120, tevap_f: 40, tcond_f: 120 }));
});

test("bounds: spec-v322 computeCondenserHeatRejection pins the 1 + 1/COP factor, the tons conversion, and error seams", () => {
  const r = _v322({ q_evap: 5, unit_tons: 1, cop: 2.4 });
  assert.ok(Math.abs(r.w_comp_btuh - 60000 / 2.4) < 1e-9);
  assert.ok(Math.abs(r.thr_btuh - 60000 * (1 + 1 / 2.4)) < 1e-9);
  assert.ok(Math.abs(r.factor - (1 + 1 / 2.4)) < 1e-12);
  assert.ok(Math.abs(r.thr_tons - r.thr_btuh / 12000) < 1e-9);
  // A worse COP piles more heat on the condenser.
  const r2 = _v322({ q_evap: 5, unit_tons: 1, cop: 1.5 });
  assert.ok(Math.abs(r2.thr_btuh - 100000) < 1e-6);
  assert.ok(r2.thr_btuh > r.thr_btuh);
  // Btu/h unit path.
  assert.ok(Math.abs(_v322({ q_evap: 60000, unit_tons: 0, cop: 2.4 }).thr_btuh - r.thr_btuh) < 1e-6);
  // Error seams.
  assert.ok("error" in _v322({ q_evap: 0, cop: 2.4 }));
  assert.ok("error" in _v322({ q_evap: 5, unit_tons: 1, cop: 0 }));
  assert.ok("error" in _v322({ q_evap: Infinity, cop: 2.4 }));
});

import { computeCondenserCopForHeatRejection as _v761 } from "../../calc-refrigerant.js";
test("bounds: spec-v761 COP implied by the heat of rejection (inverse of condenser-heat-rejection)", () => {
  const p = _v761({ q_evap: 60000, target_thr: 100000, unit_tons: 0 });
  assert.ok(Math.abs(p.cop - 1.5) < 1e-9);
  assert.ok(Math.abs(p.w_comp_btuh - 40000) < 1e-9);
  assert.ok(Math.abs(p.factor - 100000 / 60000) < 1e-9);
  // round-trip: the recovered COP fed to condenser-heat-rejection reproduces the target THR
  for (const [q, thr, unit] of [[60000, 100000, 0], [5, 7.0833, 1], [36000, 51000, 0], [10, 12.5, 1]]) {
    const inv = _v761({ q_evap: q, target_thr: thr, unit_tons: unit });
    const fwd = _v322({ q_evap: q, unit_tons: unit, cop: inv.cop });
    const thr_btuh = unit === 1 ? thr * 12000 : thr;
    assert.ok(Math.abs(fwd.thr_btuh - thr_btuh) < 1e-3);
  }
  // a higher heat of rejection (more compressor work) means a lower COP
  assert.ok(_v761({ q_evap: 60000, target_thr: 120000 }).cop < _v761({ q_evap: 60000, target_thr: 100000 }).cop);
  // tons unit path matches the Btu/h path (COP is a ratio)
  assert.ok(Math.abs(_v761({ q_evap: 5, target_thr: 8.3333, unit_tons: 1 }).cop - _v761({ q_evap: 60000, target_thr: 100000, unit_tons: 0 }).cop) < 1e-3);
  // error seams: non-positive q/thr, thr <= q, non-finite
  assert.ok("error" in _v761({ q_evap: 0, target_thr: 100000 }));
  assert.ok("error" in _v761({ q_evap: 60000, target_thr: 0 }));
  assert.ok("error" in _v761({ q_evap: 60000, target_thr: 60000 })); // thr == q (no compressor work)
  assert.ok("error" in _v761({ q_evap: 60000, target_thr: 50000 })); // thr < q
  assert.ok("error" in _v761({ q_evap: Infinity, target_thr: 100000 }));
});

// ===================== spec-v323..v325 engine-build performance batch =====================
import { computeInjectorSize as _v323, computeMeanPistonSpeed as _v324, computeTrapSpeedHorsepower as _v325 } from "../../calc-mechanic.js";

test("bounds: spec-v323 computeInjectorSize pins the injector flow, the BSFC scaling, the cc/min conversion, and error seams", () => {
  const r = _v323({ hp: 400, bsfc: 0.50, n_cyl: 8, duty: 0.80 });
  assert.strictEqual(r.total_lbh, 200);
  assert.ok(Math.abs(r.inj_lbh - 200 / (8 * 0.8)) < 1e-9);
  assert.ok(Math.abs(r.inj_ccmin - r.inj_lbh * 10.5) < 1e-9);
  // A 20% higher BSFC demands a 20% bigger injector.
  const r2 = _v323({ hp: 400, bsfc: 0.60, n_cyl: 8, duty: 0.80 });
  assert.ok(Math.abs(r2.inj_lbh / r.inj_lbh - 1.2) < 1e-9);
  // Error seams.
  assert.ok("error" in _v323({ hp: 0, bsfc: 0.5, n_cyl: 8, duty: 0.8 }));
  assert.ok("error" in _v323({ hp: 400, bsfc: 0, n_cyl: 8, duty: 0.8 }));
  assert.ok("error" in _v323({ hp: 400, bsfc: 0.5, n_cyl: 0, duty: 0.8 }));
  assert.ok("error" in _v323({ hp: 400, bsfc: 0.5, n_cyl: 8, duty: 1.5 }));
  assert.ok("error" in _v323({ hp: Infinity, bsfc: 0.5, n_cyl: 8, duty: 0.8 }));
});

import { computeInjectorMaxHp as _v661 } from "../../calc-mechanic.js";

test("bounds: spec-v661 computeInjectorMaxHp inverts the injector sizing, round-trips it, handles cc/min, and pins error seams", () => {
  const r = _v661({ inj_flow: 31.25, flow_unit: "lbh", n_cyl: 8, duty: 0.80, bsfc: 0.50 });
  assert.ok(Math.abs(r.hp_max - 400) < 1e-9); // 31.25 * 8 * 0.8 / 0.5
  assert.ok(Math.abs(r.total_lbh - 200) < 1e-9);
  // Exact inverse of injector-size: the per-injector flow for that HP is the entered flow.
  assert.ok(Math.abs(_v323({ hp: r.hp_max, bsfc: 0.50, n_cyl: 8, duty: 0.80 }).inj_lbh - 31.25) < 1e-9);
  // A richer boosted tune (higher BSFC) supports less power for the same injectors.
  assert.ok(Math.abs(_v661({ inj_flow: 31.25, flow_unit: "lbh", n_cyl: 8, duty: 0.80, bsfc: 0.60 }).hp_max - 200 / 0.60) < 1e-9);
  // cc/min input converts by 10.5: 328.125 cc/min = 31.25 lb/h -> the same 400 hp.
  assert.ok(Math.abs(_v661({ inj_flow: 328.125, flow_unit: "ccmin", n_cyl: 8, duty: 0.80, bsfc: 0.50 }).hp_max - 400) < 1e-9);
  // Error seams: non-positive flow, bad injector count, out-of-range duty, non-finite.
  assert.ok("error" in _v661({ inj_flow: 0, flow_unit: "lbh", n_cyl: 8, duty: 0.80, bsfc: 0.50 }));
  assert.ok("error" in _v661({ inj_flow: 31.25, flow_unit: "lbh", n_cyl: 0, duty: 0.80, bsfc: 0.50 }));
  assert.ok("error" in _v661({ inj_flow: 31.25, flow_unit: "lbh", n_cyl: 8, duty: 1.5, bsfc: 0.50 }));
  assert.ok("error" in _v661({ inj_flow: Infinity, flow_unit: "lbh", n_cyl: 8, duty: 0.80, bsfc: 0.50 }));
});

test("bounds: spec-v324 computeMeanPistonSpeed pins the ft/min, the m/s conversion, the regime bands, and error seams", () => {
  const r = _v324({ stroke_in: 3.48, rpm: 6000 });
  assert.ok(Math.abs(r.mps_fpm - 3.48 * 6000 / 6) < 1e-9);
  assert.ok(Math.abs(r.mps_ms - r.mps_fpm * 0.00508) < 1e-9);
  assert.ok(r.regime.startsWith("street"));
  // Revving crosses into performance.
  assert.ok(_v324({ stroke_in: 3.48, rpm: 7000 }).regime.startsWith("performance"));
  // A high speed crosses into race-only.
  assert.ok(_v324({ stroke_in: 4.0, rpm: 8000 }).regime.startsWith("race"));
  // Error seams.
  assert.ok("error" in _v324({ stroke_in: 0, rpm: 6000 }));
  assert.ok("error" in _v324({ stroke_in: 3.48, rpm: 0 }));
  assert.ok("error" in _v324({ stroke_in: NaN, rpm: 6000 }));
});

import { computeMaxRpmFromPistonSpeed as _v660 } from "../../calc-mechanic.js";

test("bounds: spec-v660 computeMaxRpmFromPistonSpeed inverts the mean-piston-speed relation, round-trips it, scales inversely with stroke, and pins error seams", () => {
  const r = _v660({ stroke_in: 3.48, mps_limit_fpm: 4000 });
  assert.ok(Math.abs(r.rpm_max - 6 * 4000 / 3.48) < 1e-9); // ~6897
  assert.ok(Math.abs(r.mps_limit_ms - 4000 * 0.00508) < 1e-9);
  // Exact inverse of mean-piston-speed: the RPM cap, fed back, gives exactly the limit.
  assert.ok(Math.abs(_v324({ stroke_in: 3.48, rpm: r.rpm_max }).mps_fpm - 4000) < 1e-9);
  // A longer stroke lowers the cap for the same limit (4.0 in at 4000 -> 6000 rpm).
  assert.ok(Math.abs(_v660({ stroke_in: 4.0, mps_limit_fpm: 4000 }).rpm_max - 6000) < 1e-9);
  // A higher piston-speed ceiling raises the cap proportionally.
  assert.ok(Math.abs(_v660({ stroke_in: 3.48, mps_limit_fpm: 4500 }).rpm_max - r.rpm_max * 4500 / 4000) < 1e-6);
  // Error seams: non-positive stroke / limit, non-finite.
  assert.ok("error" in _v660({ stroke_in: 0, mps_limit_fpm: 4000 }));
  assert.ok("error" in _v660({ stroke_in: 3.48, mps_limit_fpm: 0 }));
  assert.ok("error" in _v660({ stroke_in: NaN, mps_limit_fpm: 4000 }));
});

test("bounds: spec-v325 computeTrapSpeedHorsepower pins the cube law, the ET companion, and error seams", () => {
  const r = _v325({ weight_lb: 3200, trap_mph: 108 });
  assert.ok(Math.abs(r.hp - 3200 * Math.pow(108 / 234, 3)) < 1e-9);
  assert.ok(Math.abs(r.hp - 315) < 1);
  assert.ok(Math.abs(r.et_s - 5.825 * Math.pow(3200 / r.hp, 1 / 3)) < 1e-9);
  // The cube law: a 6.5% faster trap is ~20% more power.
  const r2 = _v325({ weight_lb: 3200, trap_mph: 115 });
  assert.ok(Math.abs(r2.hp - 380) < 1);
  assert.ok(Math.abs(r2.hp / r.hp - Math.pow(115 / 108, 3)) < 1e-9);
  // Error seams.
  assert.ok("error" in _v325({ weight_lb: 0, trap_mph: 108 }));
  assert.ok("error" in _v325({ weight_lb: 3200, trap_mph: 0 }));
  assert.ok("error" in _v325({ weight_lb: Infinity, trap_mph: 108 }));
});

import { computeEtHorsepower as _v662 } from "../../calc-mechanic.js";

test("bounds: spec-v662 computeEtHorsepower inverts the ET relation, round-trips the trap-speed tile, follows the cube law, and pins error seams", () => {
  const r = _v662({ weight_lb: 3200, et_s: 12.63 });
  assert.ok(Math.abs(r.hp - 3200 * Math.pow(5.825 / 12.63, 3)) < 1e-9); // ~314
  assert.ok(Math.abs(r.hp - 314) < 1);
  // Exact inverse of the trap-speed tile's ET: feed its computed ET back and recover the HP.
  const fwd = _v325({ weight_lb: 3200, trap_mph: 108 });
  assert.ok(Math.abs(_v662({ weight_lb: 3200, et_s: fwd.et_s }).hp - fwd.hp) < 1e-9);
  // Cube law: a quicker ET implies more power.
  assert.ok(_v662({ weight_lb: 3200, et_s: 11.5 }).hp > r.hp);
  assert.ok(Math.abs(_v662({ weight_lb: 3200, et_s: 11.5 }).hp - 416) < 1);
  // Error seams: non-positive weight / ET, non-finite.
  assert.ok("error" in _v662({ weight_lb: 0, et_s: 12.63 }));
  assert.ok("error" in _v662({ weight_lb: 3200, et_s: 0 }));
  assert.ok("error" in _v662({ weight_lb: 3200, et_s: Infinity }));
});

