test("bounds: spec-v327 computeSoilPhaseRelations pins the phase relations, the S identity, and error seams", () => {
  const r = _v327({ gamma_pcf: 120, w_pct: 15, gs: 2.70 });
  assert.ok(Math.abs(r.gamma_d_pcf - 120 / 1.15) < 1e-9);
  assert.ok(Math.abs(r.e_ratio - (2.70 * 62.4 / r.gamma_d_pcf - 1)) < 1e-9);
  assert.ok(Math.abs(r.n_porosity - r.e_ratio / (1 + r.e_ratio)) < 1e-12);
  assert.ok(Math.abs(r.s_pct - (0.15 * 2.70 / r.e_ratio) * 100) < 1e-9);
  // Saturating the skeleton drives S to ~100%.
  const r2 = _v327({ gamma_pcf: 128, w_pct: 22.78, gs: 2.70 });
  assert.ok(Math.abs(r2.s_pct - 100) < 1);
  // Error seams.
  assert.ok("error" in _v327({ gamma_pcf: 0, w_pct: 15, gs: 2.70 }));
  assert.ok("error" in _v327({ gamma_pcf: 120, w_pct: 15, gs: 0 }));
  assert.ok("error" in _v327({ gamma_pcf: 200, w_pct: 0, gs: 2.70 })); // impossibly dense -> e <= 0
  assert.ok("error" in _v327({ gamma_pcf: NaN, w_pct: 15, gs: 2.70 }));
});

test("bounds: spec-v328 computeAtterbergIndices pins the A-line classification, the LL split, and error seams", () => {
  const r = _v328({ ll: 45, pl: 22, w_pct: 30 });
  assert.strictEqual(r.pi, 23);
  assert.ok(Math.abs(r.aline - 0.73 * 25) < 1e-9);
  assert.strictEqual(r.above_a, true);
  assert.strictEqual(r.group, "CL (lean clay)");
  assert.ok(Math.abs(r.li - (30 - 22) / 23) < 1e-9);
  // A low-PI soil below the A-line is a silt.
  const r2 = _v328({ ll: 30, pl: 25, w_pct: 28 });
  assert.strictEqual(r2.above_a, false);
  assert.strictEqual(r2.group, "ML (silt)");
  // The LL = 50 split: a high-LL clay is CH.
  assert.strictEqual(_v328({ ll: 60, pl: 25 }).group, "CH (fat clay)");
  assert.strictEqual(_v328({ ll: 60, pl: 55 }).group, "MH (elastic silt)"); // PI 5 below A-line 29.2
  // Omitting water content leaves LI null.
  assert.strictEqual(_v328({ ll: 45, pl: 22 }).li, null);
  // Error seams.
  assert.ok("error" in _v328({ ll: 0, pl: 22 }));
  assert.ok("error" in _v328({ ll: 20, pl: 25 })); // PL >= LL nonplastic
  assert.ok("error" in _v328({ ll: NaN, pl: 22 }));
});

// ===================== spec-v329..v331 building-energy batch =====================
import { computeBuildingUa as _v329, computeDegreeDayEnergy as _v330, computeWallCondensationGradient as _v331 } from "../../calc-hvac.js";

test("bounds: spec-v329 computeBuildingUa pins the assembly sum, the infiltration term, the design load, and error seams", () => {
  const asm = [{ area: 1200, r: 17 }, { area: 1500, r: 38 }, { area: 200, r: 3 }, { area: 1500, r: 19 }];
  const r = _v329({ assemblies: asm, cfm_inf: 50, dt_f: 70 });
  assert.ok(Math.abs(r.cond - (1200 / 17 + 1500 / 38 + 200 / 3 + 1500 / 19)) < 1e-9);
  assert.ok(Math.abs(r.ua_inf - 1.08 * 50) < 1e-9);
  assert.ok(Math.abs(r.ua - (r.cond + r.ua_inf)) < 1e-12);
  assert.ok(Math.abs(r.ua - 309.7) < 0.1);
  assert.ok(Math.abs(r.design_load - r.ua * 70) < 1e-9);
  // No dT -> null load.
  assert.strictEqual(_v329({ assemblies: asm, cfm_inf: 50 }).design_load, null);
  // Error seams.
  assert.ok("error" in _v329({ assemblies: [], cfm_inf: 50 }));
  assert.ok("error" in _v329({ assemblies: [{ area: 0, r: 17 }], cfm_inf: 50 }));
  assert.ok("error" in _v329({ assemblies: [{ area: 1200, r: 0 }], cfm_inf: 50 }));
  assert.ok("error" in _v329({ assemblies: asm, cfm_inf: -5 }));
  assert.ok("error" in _v329({ assemblies: asm, cfm_inf: Infinity }));
});

test("bounds: spec-v330 computeDegreeDayEnergy pins the degree-day energy, the fuel conversions, and error seams", () => {
  const r = _v330({ ua_btuhf: 500, hdd: 5000, eff: 0.80, fuel: "gas", price: 1.20 });
  assert.ok(Math.abs(r.q_mmbtu - 24 * 5000 * 500 / 1e6) < 1e-9);
  assert.ok(Math.abs(r.fuel_units - 750) < 1e-6);
  assert.strictEqual(r.unit_label, "therms");
  assert.ok(Math.abs(r.cost - 900) < 1e-6);
  // The heat-pump/electric path.
  const r2 = _v330({ ua_btuhf: 500, hdd: 5000, eff: 3.0, fuel: "electric", price: 0.15 });
  assert.ok(Math.abs(r2.fuel_units - 24 * 5000 * 500 / 3.0 / 3412) < 1e-6);
  assert.strictEqual(r2.unit_label, "kWh");
  // Oil path.
  assert.strictEqual(_v330({ ua_btuhf: 500, hdd: 5000, eff: 0.85, fuel: "oil", price: 3.5 }).unit_label, "gal");
  // Error seams.
  assert.ok("error" in _v330({ ua_btuhf: 0, hdd: 5000, eff: 0.8, fuel: "gas" }));
  assert.ok("error" in _v330({ ua_btuhf: 500, hdd: 0, eff: 0.8, fuel: "gas" }));
  assert.ok("error" in _v330({ ua_btuhf: 500, hdd: 5000, eff: 0, fuel: "gas" }));
  assert.ok("error" in _v330({ ua_btuhf: 500, hdd: 5000, eff: 0.8, fuel: "bogus" }));
  assert.ok("error" in _v330({ ua_btuhf: Infinity, hdd: 5000, eff: 0.8, fuel: "gas" }));
});

test("bounds: spec-v331 computeWallCondensationGradient pins the gradient, the dew point, the condensing flag, and error seams", () => {
  const r = _v331({ r_inside: 13.5, r_outside: 4, t_in_f: 70, t_out_f: 20, rh_in_pct: 40 });
  assert.ok(Math.abs(r.t_plane_f - (70 - (13.5 / 17.5) * 50)) < 1e-9);
  assert.ok(Math.abs(r.t_plane_f - 31.4) < 0.1);
  assert.ok(Math.abs(r.t_dew_f - 44.6) < 0.3);
  assert.ok(r.margin_f < 0);
  assert.strictEqual(r.condensing, true);
  // Adding exterior insulation warms the plane.
  const r2 = _v331({ r_inside: 13.5, r_outside: 9, t_in_f: 70, t_out_f: 20, rh_in_pct: 40 });
  assert.ok(r2.t_plane_f > r.t_plane_f);
  assert.ok(Math.abs(r2.t_plane_f - 40.0) < 0.1);
  // Error seams.
  assert.ok("error" in _v331({ r_inside: 0, r_outside: 4, t_in_f: 70, t_out_f: 20, rh_in_pct: 40 }));
  assert.ok("error" in _v331({ r_inside: 13.5, r_outside: 0, t_in_f: 70, t_out_f: 20, rh_in_pct: 40 }));
  assert.ok("error" in _v331({ r_inside: 13.5, r_outside: 4, t_in_f: 70, t_out_f: 20, rh_in_pct: 0 }));
  assert.ok("error" in _v331({ r_inside: 13.5, r_outside: 4, t_in_f: 70, t_out_f: 20, rh_in_pct: 120 }));
  assert.ok("error" in _v331({ r_inside: NaN, r_outside: 4, t_in_f: 70, t_out_f: 20, rh_in_pct: 40 }));
});

// ===================== spec-v332..v334 wood-fastener withdrawal batch =====================
import { computeWoodNailWithdrawal as _v332, computeWoodLagWithdrawal as _v333, computeWoodScrewWithdrawal as _v334 } from "../../calc-construction.js";

test("bounds: spec-v332 computeWoodNailWithdrawal pins the G^2.5 value, the toenail/CD factors, and error seams", () => {
  const r = _v332({ g: 0.50, d_in: 0.162, p_in: 1.5, cd: 1.0, toenail: "no" });
  assert.ok(Math.abs(r.w_lbin - 1380 * Math.pow(0.5, 2.5) * 0.162) < 1e-9);
  assert.ok(Math.abs(r.w_lbin - 39.5) < 0.1);
  assert.ok(Math.abs(r.z_w - r.w_lbin * 1.5) < 1e-9);
  // Toenailed at wind duration applies both factors.
  const r2 = _v332({ g: 0.50, d_in: 0.162, p_in: 1.5, cd: 1.6, toenail: "yes" });
  assert.strictEqual(r2.ctn, 0.67);
  assert.ok(Math.abs(r2.z_w - r.w_lbin * 1.5 * 1.6 * 0.67) < 1e-9);
  // Error seams.
  assert.ok("error" in _v332({ g: 0, d_in: 0.162, p_in: 1.5 }));
  assert.ok("error" in _v332({ g: 0.5, d_in: 0, p_in: 1.5 }));
  assert.ok("error" in _v332({ g: 0.5, d_in: 0.162, p_in: 0 }));
  assert.ok("error" in _v332({ g: Infinity, d_in: 0.162, p_in: 1.5 }));
});

test("bounds: spec-v333 computeWoodLagWithdrawal pins the D^0.75 law, the end-grain factor, and error seams", () => {
  const r = _v333({ g: 0.50, d_in: 0.5, p_thread_in: 4, cd: 1.0, end_grain: "no" });
  assert.ok(Math.abs(r.w_lbin - 1800 * Math.pow(0.5, 1.5) * Math.pow(0.5, 0.75)) < 1e-9);
  assert.ok(Math.abs(r.z_w - 1514) < 2);
  // A 25% larger diameter buys only ~18% more (D^0.75).
  const r2 = _v333({ g: 0.50, d_in: 0.625, p_thread_in: 4, cd: 1.0 });
  assert.ok(Math.abs(r2.z_w / r.z_w - Math.pow(0.625 / 0.5, 0.75)) < 1e-9);
  // End grain applies the 0.75 factor.
  const r3 = _v333({ g: 0.50, d_in: 0.5, p_thread_in: 4, cd: 1.0, end_grain: "yes" });
  assert.strictEqual(r3.ceg, 0.75);
  assert.ok(Math.abs(r3.z_w - r.z_w * 0.75) < 1e-9);
  // Error seams.
  assert.ok("error" in _v333({ g: 0, d_in: 0.5, p_thread_in: 4 }));
  assert.ok("error" in _v333({ g: 0.5, d_in: 0.5, p_thread_in: 0 }));
  assert.ok("error" in _v333({ g: 0.5, d_in: NaN, p_thread_in: 4 }));
});

test("bounds: spec-v334 computeWoodScrewWithdrawal pins the G^2 law and error seams", () => {
  const r = _v334({ g: 0.50, d_in: 0.190, p_in: 1.0, cd: 1.0 });
  assert.ok(Math.abs(r.w_lbin - 2850 * 0.25 * 0.190) < 1e-9);
  assert.ok(Math.abs(r.w_lbin - 135.375) < 0.1);
  assert.ok(Math.abs(r.z_w - r.w_lbin) < 1e-9);
  // A softer species drops with G^2.
  const r2 = _v334({ g: 0.42, d_in: 0.190, p_in: 1.0, cd: 1.0 });
  assert.ok(Math.abs(r2.w_lbin / r.w_lbin - Math.pow(0.42 / 0.50, 2)) < 1e-9);
  // Error seams.
  assert.ok("error" in _v334({ g: 0, d_in: 0.190, p_in: 1.0 }));
  assert.ok("error" in _v334({ g: 0.5, d_in: 0.190, p_in: 0 }));
  assert.ok("error" in _v334({ g: 0.5, d_in: 0.190, p_in: 1.0, cd: 0 }));
  assert.ok("error" in _v334({ g: Infinity, d_in: 0.190, p_in: 1.0 }));
});

// ===================== spec-v335..v337 roadway geometric-design batch =====================
import { computeSuperelevation as _v335, computeVerticalCurveSightDistance as _v336, computeHorizontalSightlineOffset as _v337 } from "../../calc-civil.js";

test("bounds: spec-v335 computeSuperelevation pins both modes, the no-bank case, and error seams", () => {
  const e = _v335({ mode: "e", V_mph: 60, R_ft: 1500, f: 0.12 });
  assert.ok(Math.abs(e.e_req - 0.04) < 1e-9);
  assert.strictEqual(e.no_bank, false);
  const rm = _v335({ mode: "rmin", V_mph: 60, e_max: 0.08, f: 0.12 });
  assert.ok(Math.abs(rm.R_min_ft - 1200) < 1e-6);
  // A flatter curve needs no bank (negative required e).
  const nb = _v335({ mode: "e", V_mph: 60, R_ft: 3000, f: 0.12 });
  assert.ok(nb.e_req < 0 && nb.no_bank === true);
  // Error seams.
  assert.ok("error" in _v335({ mode: "e", V_mph: 0, R_ft: 1500, f: 0.12 }));
  assert.ok("error" in _v335({ mode: "e", V_mph: 60, R_ft: 0, f: 0.12 }));
  assert.ok("error" in _v335({ mode: "rmin", V_mph: 60, e_max: 0, f: 0 }));
  assert.ok("error" in _v335({ mode: "e", V_mph: Infinity, R_ft: 1500, f: 0.12 }));
});

import { computeSuperelevationSafeCurveSpeed as _v756 } from "../../calc-civil.js";
test("bounds: spec-v756 safe curve speed from radius and superelevation (inverse of superelevation)", () => {
  const p = _v756({ R_ft: 1500, e: 0.08, f: 0.12 });
  assert.ok(Math.abs(p.v_mph - 67.082) < 0.01);
  // round-trip: the recovered speed fed to superelevation (mode e) at the same radius/f gives back e
  for (const [R, e, f] of [[1500, 0.08, 0.12], [1000, 0.06, 0.14], [2500, 0.04, 0.10], [800, 0.10, 0.16]]) {
    const inv = _v756({ R_ft: R, e, f });
    const fwd = _v335({ mode: "e", V_mph: inv.v_mph, R_ft: R, f });
    assert.ok(Math.abs(fwd.e_req - e) < 1e-9);
  }
  // a larger radius or a higher bank+friction supports a higher speed
  assert.ok(_v756({ R_ft: 3000, e: 0.08, f: 0.12 }).v_mph > _v756({ R_ft: 1500, e: 0.08, f: 0.12 }).v_mph);
  assert.ok(_v756({ R_ft: 1500, e: 0.10, f: 0.14 }).v_mph > _v756({ R_ft: 1500, e: 0.08, f: 0.12 }).v_mph);
  // error seams: non-positive radius, e+f <= 0, non-finite
  assert.ok("error" in _v756({ R_ft: 0, e: 0.08, f: 0.12 }));
  assert.ok("error" in _v756({ R_ft: 1500, e: -0.12, f: 0.12 })); // e + f = 0
  assert.ok("error" in _v756({ R_ft: 1500, e: -0.2, f: 0.1 })); // e + f < 0
  assert.ok("error" in _v756({ R_ft: Infinity, e: 0.08, f: 0.12 }));
});

test("bounds: spec-v336 computeVerticalCurveSightDistance pins the branch switch, K, and error seams", () => {
  const a = _v336({ A_pct: 5, S_ft: 570, C: 2158 });
  assert.ok(Math.abs(a.L_ft - 752.8) < 1);
  assert.strictEqual(a.branch, "S <= L");
  assert.ok(Math.abs(a.K_ft_per_pct - a.L_ft / 5) < 1e-9);
  // A gentler grade change flips to the S > L branch and a shorter length.
  const b = _v336({ A_pct: 3, S_ft: 570, C: 2158 });
  assert.strictEqual(b.branch, "S > L");
  assert.ok(Math.abs(b.L_ft - 420.7) < 1);
  assert.ok(b.L_ft < a.L_ft);
  // Default constant is 2158 when C omitted.
  assert.ok(Math.abs(_v336({ A_pct: 5, S_ft: 570 }).L_ft - a.L_ft) < 1e-9);
  // Error seams.
  assert.ok("error" in _v336({ A_pct: 0, S_ft: 570 }));
  assert.ok("error" in _v336({ A_pct: 5, S_ft: 0 }));
  assert.ok("error" in _v336({ A_pct: NaN, S_ft: 570 }));
});

test("bounds: spec-v337 computeHorizontalSightlineOffset pins the forward/inverse round-trip, sensitivity, and error seams", () => {
  const m = _v337({ mode: "M", R_ft: 1000, S_ft: 570 });
  assert.ok(Math.abs(m.M_ft - 40.3) < 0.1);
  // Inverse recovers S from M (round-trip).
  const s = _v337({ mode: "maxS", R_ft: 1000, M_ft: m.M_ft });
  assert.ok(Math.abs(s.S_ft - 570) < 0.1);
  // A tighter radius drives the clear-zone wider.
  const m2 = _v337({ mode: "M", R_ft: 600, S_ft: 570 });
  assert.ok(m2.M_ft > m.M_ft && Math.abs(m2.M_ft - 66.4) < 0.1);
  // Error seams.
  assert.ok("error" in _v337({ mode: "M", R_ft: 0, S_ft: 570 }));
  assert.ok("error" in _v337({ mode: "M", R_ft: 1000, S_ft: 0 }));
  assert.ok("error" in _v337({ mode: "maxS", R_ft: 1000, M_ft: 0 }));
  assert.ok("error" in _v337({ mode: "maxS", R_ft: 1000, M_ft: 2500 }));
  assert.ok("error" in _v337({ mode: "M", R_ft: Infinity, S_ft: 570 }));
});

