  assert.ok(Math.abs(r.LLF - 0.727) < 0.001);
  assert.ok(Math.abs(r.maintained_lm - 4000 * r.LLF) < 1e-9);
  // A cleaner system has a higher LLF.
  const clean = _v365({ LLD: 0.95, LDD: 0.95, BF: 0.98 });
