import { computeClarifierAreaForLoading as _v742 } from "../../calc-treatment.js";
test("bounds: spec-v742 clarifier surface area for a target SOR (inverse of clarifier-surface-loading)", () => {
  const p = _v742({ flow_mgd: 1.0, target_sor_gpd_ft2: 800 });
  assert.ok(Math.abs(p.required_area_ft2 - 1250) < 1e-6);
  assert.ok(Math.abs(p.equiv_diameter_ft - Math.sqrt(4 * 1250 / Math.PI)) < 1e-9);
  // round-trip: the recovered area fed to clarifier-surface-loading reproduces the target SOR
  for (const [flow, sor] of [[1.0, 800], [2.5, 700], [0.5, 1000], [4.0, 600]]) {
    const inv = _v742({ flow_mgd: flow, target_sor_gpd_ft2: sor });
    const fwd = _v405({ flow_mgd: flow, surface_ft2: inv.required_area_ft2, weir_len_ft: 100 });
    assert.ok(Math.abs(fwd.sor_gpd_ft2 - sor) < 1e-6);
  }
  // a lower target SOR needs more area; a higher flow needs more area (monotonic)
  assert.ok(_v742({ flow_mgd: 1.0, target_sor_gpd_ft2: 700 }).required_area_ft2 > _v742({ flow_mgd: 1.0, target_sor_gpd_ft2: 1000 }).required_area_ft2);
  assert.ok(_v742({ flow_mgd: 2.0, target_sor_gpd_ft2: 800 }).required_area_ft2 > _v742({ flow_mgd: 1.0, target_sor_gpd_ft2: 800 }).required_area_ft2);
  // error seams
  assert.ok("error" in _v742({ flow_mgd: 0, target_sor_gpd_ft2: 800 }));
  assert.ok("error" in _v742({ flow_mgd: 1.0, target_sor_gpd_ft2: 0 }));
  assert.ok("error" in _v742({ flow_mgd: Infinity, target_sor_gpd_ft2: 800 }));
});

test("bounds: spec-v406 computeBodTssLoadingRemoval pins the loads, removal, the upset case, and error seams", () => {
  const r = _v406({ flow_mgd: 1.0, influent_mgl: 200, effluent_mgl: 20 });
  assert.ok(Math.abs(r.influent_lb_day - 1668) < 1e-6);
  assert.ok(Math.abs(r.removed_lb_day - 1501.2) < 1e-6);
  assert.ok(Math.abs(r.removal_pct - 90) < 1e-9 && r.upset === false);
  // Load scales with flow; efficiency does not.
  const big = _v406({ flow_mgd: 4.0, influent_mgl: 200, effluent_mgl: 20 });
  assert.ok(Math.abs(big.influent_lb_day - 6672) < 1e-6 && Math.abs(big.removal_pct - 90) < 1e-9);
  // An effluent above influent is a reported upset, not an error.
  const upset = _v406({ flow_mgd: 1.0, influent_mgl: 20, effluent_mgl: 30 });
  assert.ok(upset.removal_pct < 0 && upset.upset === true && !("error" in upset));
  // Error seams.
  assert.ok("error" in _v406({ flow_mgd: 0, influent_mgl: 200, effluent_mgl: 20 }));
  assert.ok("error" in _v406({ flow_mgd: 1.0, influent_mgl: 0, effluent_mgl: 20 }));
  assert.ok("error" in _v406({ flow_mgd: Infinity, influent_mgl: 200, effluent_mgl: 20 }));
});

test("bounds: spec-v407 computeTdsFromConductivity pins TDS, the k-band, and error seams", () => {
  const r = _v407({ conductivity_us_cm: 1000, k_factor: 0.65 });
  assert.ok(Math.abs(r.tds_mgl - 650) < 1e-9);
  assert.ok(Math.abs(r.tds_low - 550) < 1e-9 && Math.abs(r.tds_high - 750) < 1e-9);
  // A different factor scales linearly.
  assert.ok(Math.abs(_v407({ conductivity_us_cm: 1000, k_factor: 0.55 }).tds_mgl - 550) < 1e-9);
  // Error seams: non-positive EC, out-of-range factor, non-finite.
  assert.ok("error" in _v407({ conductivity_us_cm: 0, k_factor: 0.65 }));
  assert.ok("error" in _v407({ conductivity_us_cm: 1000, k_factor: 1.5 }));
  assert.ok("error" in _v407({ conductivity_us_cm: 1000, k_factor: 0.3 }));
  assert.ok("error" in _v407({ conductivity_us_cm: Infinity, k_factor: 0.65 }));
});

import { computeConductivityFromTds as _v657 } from "../../calc-treatment.js";

test("bounds: spec-v657 computeConductivityFromTds inverts the TDS estimate, round-trips it, pins the k-band, and rejects bad inputs", () => {
  const r = _v657({ tds_mgl: 650, k_factor: 0.65 });
  assert.ok(Math.abs(r.conductivity_us_cm - 1000) < 1e-9); // 650 / 0.65
  assert.ok(Math.abs(r.ec_low - 650 / 0.75) < 1e-9 && Math.abs(r.ec_high - 650 / 0.55) < 1e-9);
  // Exact inverse of tds-from-conductivity: feeding the EC back reproduces the TDS.
  assert.ok(Math.abs(_v407({ conductivity_us_cm: r.conductivity_us_cm, k_factor: 0.65 }).tds_mgl - 650) < 1e-9);
  // A lower factor gives a higher conductivity for the same TDS.
  assert.ok(_v657({ tds_mgl: 650, k_factor: 0.55 }).conductivity_us_cm > r.conductivity_us_cm);
  // Error seams: non-positive TDS, out-of-range factor, non-finite.
  assert.ok("error" in _v657({ tds_mgl: 0, k_factor: 0.65 }));
  assert.ok("error" in _v657({ tds_mgl: 650, k_factor: 1.5 }));
  assert.ok("error" in _v657({ tds_mgl: 650, k_factor: 0.3 }));
  assert.ok("error" in _v657({ tds_mgl: Infinity, k_factor: 0.65 }));
});

// ===================== spec-v408..v410 HVAC duct-design trio (2 modules) =====================
import { computeManualDFrictionRate as _v408 } from "../../calc-hvac.js";
import { computeCoilFaceVelocity as _v409, computeVavBoxAirflow as _v410, computeCoilFaceArea as _v701 } from "../../calc-hvacsystems.js";

test("bounds: spec-v408 computeManualDFrictionRate pins ASP/FR, the unworkable case, and error seams", () => {
  const r = _v408({ blower_esp_inwg: 0.60, component_drop_inwg: 0.42, tel_ft: 180 });
  assert.ok(Math.abs(r.asp_inwg - 0.18) < 1e-9);
  assert.ok(Math.abs(r.fr_inwg_100ft - 0.10) < 1e-9);
  // A longer run softens the rate.
  const long = _v408({ blower_esp_inwg: 0.60, component_drop_inwg: 0.42, tel_ft: 300 });
  assert.ok(Math.abs(long.fr_inwg_100ft - 0.06) < 1e-9 && long.fr_inwg_100ft < r.fr_inwg_100ft);
  // Drops meeting/exceeding the blower static is unworkable.
  assert.ok("error" in _v408({ blower_esp_inwg: 0.40, component_drop_inwg: 0.50, tel_ft: 180 }));
  // Error seams.
  assert.ok("error" in _v408({ blower_esp_inwg: 0, component_drop_inwg: 0.42, tel_ft: 180 }));
  assert.ok("error" in _v408({ blower_esp_inwg: 0.60, component_drop_inwg: 0.42, tel_ft: 0 }));
  assert.ok("error" in _v408({ blower_esp_inwg: Infinity, component_drop_inwg: 0.42, tel_ft: 180 }));
});

test("bounds: spec-v409 computeCoilFaceVelocity pins the velocity, the carryover flag, and error seams", () => {
  const r = _v409({ cfm: 2000, face_width_in: 24, face_height_in: 18, threshold_fpm: 500 });
  assert.ok(Math.abs(r.face_area_ft2 - 3.0) < 1e-9);
  assert.ok(Math.abs(r.face_velocity_fpm - 2000 / 3) < 1e-9 && r.carryover === true);
  // Lower airflow stays below the threshold.
  const low = _v409({ cfm: 1200, face_width_in: 24, face_height_in: 18, threshold_fpm: 500 });
  assert.ok(Math.abs(low.face_velocity_fpm - 400) < 1e-9 && low.carryover === false);
  // Error seams.
  assert.ok("error" in _v409({ cfm: 0, face_width_in: 24, face_height_in: 18 }));
  assert.ok("error" in _v409({ cfm: 2000, face_width_in: 0, face_height_in: 18 }));
  assert.ok("error" in _v409({ cfm: 2000, face_width_in: 24, face_height_in: 0 }));
  assert.ok("error" in _v409({ cfm: Infinity, face_width_in: 24, face_height_in: 18 }));
});

test("bounds: spec-v701 computeCoilFaceArea pins area = CFM / target_fpm, round-trips through computeCoilFaceVelocity, and error seams", () => {
  const r = _v701({ cfm: 2000, target_fpm: 500 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.face_area_ft2 - 4.0) < 1e-9, `area identity: ${r.face_area_ft2}`);
  assert.ok(Math.abs(r.square_side_in - 24) < 1e-9, `square side: ${r.square_side_in}`);
  // Round-trip: a square coil at the returned side, fed the same airflow, sits exactly at the target velocity.
  for (const cfm of [800, 2000, 6000]) {
    for (const target_fpm of [350, 500, 700]) {
      const m = _v701({ cfm, target_fpm });
      assert.ok(!m.error, `sweep cfm=${cfm} v=${target_fpm}: ${JSON.stringify(m)}`);
      assertFinite(m.face_area_ft2, "area"); assert.ok(m.face_area_ft2 > 0, "area positive");
      const back = _v409({ cfm, face_width_in: m.square_side_in, face_height_in: m.square_side_in });
      assert.ok(Math.abs(back.face_velocity_fpm - target_fpm) < 1e-6, `round-trip cfm=${cfm} v=${target_fpm}: ${back.face_velocity_fpm}`);
    }
  }
  // A lower target velocity demands a larger face.
  assert.ok(_v701({ cfm: 2000, target_fpm: 400 }).face_area_ft2 > r.face_area_ft2);
  // A non-positive target velocity defaults to 500 fpm (mirrors the forward threshold default), not an error.
  assert.ok(Math.abs(_v701({ cfm: 2000, target_fpm: 0 }).face_area_ft2 - 4.0) < 1e-9);
  // Error seams: non-positive airflow, non-finite.
  assert.ok("error" in _v701({ cfm: 0, target_fpm: 500 }));
  assert.ok("error" in _v701({ cfm: Infinity, target_fpm: 500 }));
});

test("bounds: spec-v410 computeVavBoxAirflow pins max/min, the governing branch, and error seams", () => {
  const r = _v410({ zone_sensible_btuh: 12000, supply_dt_f: 20, ventilation_cfm: 100, turndown: 0.30 });
  assert.ok(Math.abs(r.cfm_max - 12000 / (1.08 * 20)) < 1e-9);
  assert.ok(Math.abs(r.cfm_min - 0.30 * r.cfm_max) < 1e-9 && r.min_governed_by === "turndown");
  // A high ventilation minimum governs instead.
  const vent = _v410({ zone_sensible_btuh: 12000, supply_dt_f: 20, ventilation_cfm: 250, turndown: 0.30 });
  assert.ok(Math.abs(vent.cfm_min - 250) < 1e-9 && vent.min_governed_by === "ventilation");
  // Error seams.
  assert.ok("error" in _v410({ zone_sensible_btuh: 0, supply_dt_f: 20, ventilation_cfm: 100 }));
  assert.ok("error" in _v410({ zone_sensible_btuh: 12000, supply_dt_f: 0, ventilation_cfm: 100 }));
  assert.ok("error" in _v410({ zone_sensible_btuh: 12000, supply_dt_f: 20, ventilation_cfm: 100, turndown: 1.5 }));
  assert.ok("error" in _v410({ zone_sensible_btuh: Infinity, supply_dt_f: 20, ventilation_cfm: 100 }));
});

// ===================== spec-v411..v413 steel composite-beam trio (calc-steel.js) =====================
import { computeShearStudStrength as _v411, computeCompositeBeamFlexure as _v412, computeSteelCamber as _v413 } from "../../calc-steel.js";

test("bounds: spec-v411 computeShearStudStrength pins Qn (min of calc/cap), the stud count, and error seams", () => {
  const r = _v411({ asc_in2: 0.442, fc_psi: 4000, ec_psi: 3644000, fu_ksi: 65, rg: 1.0, rp: 0.75, vprime_kip: 400 });
  assert.ok(Math.abs(r.qn_calc_kip - 0.5 * 0.442 * Math.sqrt(4000 * 3644000) / 1000) < 1e-6);
  assert.ok(Math.abs(r.qn_cap_kip - 1.0 * 0.75 * 0.442 * 65) < 1e-9);
  assert.ok(Math.abs(r.qn_kip - Math.min(r.qn_calc_kip, r.qn_cap_kip)) < 1e-12 && r.cap_governs === true);
  assert.strictEqual(r.studs_each_side, 19);
  // A weaker position raises the count.
  const weak = _v411({ asc_in2: 0.442, fc_psi: 4000, ec_psi: 3644000, fu_ksi: 65, rg: 1.0, rp: 0.6, vprime_kip: 400 });
  assert.strictEqual(weak.studs_each_side, 24);
  // No V' -> null count.
  assert.strictEqual(_v411({ asc_in2: 0.442, fc_psi: 4000, ec_psi: 3644000, fu_ksi: 65, rg: 1.0, rp: 0.75, vprime_kip: 0 }).studs_each_side, null);
  // Error seams.
  assert.ok("error" in _v411({ asc_in2: 0, fc_psi: 4000, ec_psi: 3644000, fu_ksi: 65 }));
  assert.ok("error" in _v411({ asc_in2: 0.442, fc_psi: 0, ec_psi: 3644000, fu_ksi: 65 }));
  assert.ok("error" in _v411({ asc_in2: 0.442, fc_psi: 4000, ec_psi: 0, fu_ksi: 65 }));
  assert.ok("error" in _v411({ asc_in2: 0.442, fc_psi: 4000, ec_psi: 3644000, fu_ksi: Infinity }));
});

test("bounds: spec-v412 computeCompositeBeamFlexure pins C/a/phiMn, the PNA-in-steel flag, and error seams", () => {
  const r = _v412({ as_in2: 8.0, fy_ksi: 50, d_in: 16, tslab_in: 4, be_in: 90, fc_ksi: 4 });
  assert.ok(Math.abs(r.c_kip - 400) < 1e-9);
  assert.ok(Math.abs(r.a_in - 400 / (0.85 * 4 * 90)) < 1e-9 && r.pna_in_slab === true);
  assert.ok(Math.abs(r.phi_mn_kipft - 340) < 0.5);
  // A narrow slab pushes the PNA into the steel -> flag, null moment.
  const narrow = _v412({ as_in2: 8.0, fy_ksi: 50, d_in: 16, tslab_in: 4, be_in: 24, fc_ksi: 4 });
  assert.ok(narrow.a_in > 4 && narrow.pna_in_slab === false && narrow.phi_mn_kipft === null);
  // Error seams.
  assert.ok("error" in _v412({ as_in2: 0, fy_ksi: 50, d_in: 16, tslab_in: 4, be_in: 90, fc_ksi: 4 }));
  assert.ok("error" in _v412({ as_in2: 8.0, fy_ksi: 50, d_in: 16, tslab_in: 0, be_in: 90, fc_ksi: 4 }));
  assert.ok("error" in _v412({ as_in2: 8.0, fy_ksi: 50, d_in: 16, tslab_in: 4, be_in: 90, fc_ksi: Infinity }));
});

test("bounds: spec-v413 computeSteelCamber pins the deflection, the 1/4-in rounding, the flat case, and error seams", () => {
  const r = _v413({ w_kip_ft: 1.0, span_ft: 40, moi_in4: 2100, e_ksi: 29000, fraction: 0.80 });
  assert.ok(Math.abs(r.defl_in - 0.9458) < 0.005);
  assert.ok(Math.abs(r.camber_in - 0.75) < 1e-12 && r.cambered === true);
  // Camber is a multiple of 1/4 in.
  assert.ok(Math.abs((r.camber_in / 0.25) - Math.round(r.camber_in / 0.25)) < 1e-9);
  // A short/stiff beam is left flat.
  const flat = _v413({ w_kip_ft: 0.5, span_ft: 20, moi_in4: 1350, e_ksi: 29000, fraction: 0.80 });
  assert.ok(flat.camber_in === 0 && flat.cambered === false);
  // Error seams.
  assert.ok("error" in _v413({ w_kip_ft: 0, span_ft: 40, moi_in4: 2100 }));
  assert.ok("error" in _v413({ w_kip_ft: 1.0, span_ft: 0, moi_in4: 2100 }));
  assert.ok("error" in _v413({ w_kip_ft: 1.0, span_ft: 40, moi_in4: 0 }));
  assert.ok("error" in _v413({ w_kip_ft: 1.0, span_ft: 40, moi_in4: 2100, fraction: 1.5 }));
  assert.ok("error" in _v413({ w_kip_ft: Infinity, span_ft: 40, moi_in4: 2100 }));
});

import { computeSteelInertiaForDeflection as _v754 } from "../../calc-steel.js";
test("bounds: spec-v754 required moment of inertia for a deflection limit (inverse of steel-camber)", () => {
  const p = _v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 1.0, e_ksi: 29000 });
  assert.ok(Math.abs(p.required_moi_in4 - 1986.2) < 1);
  assert.ok(Math.abs(p.span_over_defl - 480) < 1e-9);
  // round-trip: the recovered Ix fed to steel-camber reproduces the deflection limit
  for (const [w, span, defl, e] of [[1.0, 40, 1.0, 29000], [0.8, 30, 30 * 12 / 360, 29000], [2.0, 50, 50 * 12 / 240, 29000], [1.5, 24, 0.6, 29000]]) {
    const inv = _v754({ w_kip_ft: w, span_ft: span, allow_defl_in: defl, e_ksi: e });
    const fwd = _v413({ w_kip_ft: w, span_ft: span, moi_in4: inv.required_moi_in4, e_ksi: e });
    assert.ok(Math.abs(fwd.defl_in - defl) < 1e-6);
  }
  // a tighter (smaller) allowable deflection needs a stiffer section; a longer span needs much more (L^4)
  assert.ok(_v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 0.5 }).required_moi_in4 > _v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 1.0 }).required_moi_in4);
  assert.ok(_v754({ w_kip_ft: 1.0, span_ft: 50, allow_defl_in: 1.0 }).required_moi_in4 > 2 * _v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 1.0 }).required_moi_in4);
  // error seams
  assert.ok("error" in _v754({ w_kip_ft: 0, span_ft: 40, allow_defl_in: 1.0 }));
  assert.ok("error" in _v754({ w_kip_ft: 1.0, span_ft: 0, allow_defl_in: 1.0 }));
  assert.ok("error" in _v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 0 }));
  assert.ok("error" in _v754({ w_kip_ft: 1.0, span_ft: 40, allow_defl_in: 1.0, e_ksi: 0 }));
  assert.ok("error" in _v754({ w_kip_ft: Infinity, span_ft: 40, allow_defl_in: 1.0 }));
});

// ===================== spec-v414..v416 geotechnical settlement/foundation trio (calc-geotech.js) =====================
import { computeConsolidationTimeRate as _v414, computeSptBearingCapacity as _v415, computeLiquefactionScreening as _v416 } from "../../calc-geotech.js";

test("bounds: spec-v414 computeConsolidationTimeRate pins the piecewise Tv, the time, and error seams", () => {
  const r = _v414({ u_percent: 90, cv_ft2_day: 0.1, hdr_ft: 10 });
  assert.ok(Math.abs(r.tv - (1.781 - 0.933 * Math.log10(10))) < 1e-9);
  assert.ok(Math.abs(r.t_days - 848) < 1);
  // The U <= 60 branch uses the parabolic form.
  const half = _v414({ u_percent: 50, cv_ft2_day: 0.1, hdr_ft: 10 });
  assert.ok(Math.abs(half.tv - (Math.PI / 4) * 0.25) < 1e-9 && Math.abs(half.t_days - 196) < 1);
  // Doubling the drainage path quadruples the time.
  assert.ok(Math.abs(_v414({ u_percent: 90, cv_ft2_day: 0.1, hdr_ft: 20 }).t_days - 4 * r.t_days) < 1e-6);
  // Error seams.
  assert.ok("error" in _v414({ u_percent: 100, cv_ft2_day: 0.1, hdr_ft: 10 }));
  assert.ok("error" in _v414({ u_percent: 90, cv_ft2_day: 0, hdr_ft: 10 }));
  assert.ok("error" in _v414({ u_percent: 90, cv_ft2_day: 0.1, hdr_ft: 0 }));
  assert.ok("error" in _v414({ u_percent: 90, cv_ft2_day: Infinity, hdr_ft: 10 }));
});

import { computeConsolidationDegree as _v645 } from "../../calc-geotech.js";

test("bounds: spec-v645 computeConsolidationDegree inverts Terzaghi for U, round-trips the time tile across both branches, and pins error seams", () => {
  const r = _v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: 848 });
  assert.ok(Math.abs(r.tv - 0.848) < 1e-9);
  assert.ok(Math.abs(r.u_percent - 90) < 1e-9); // upper branch, exact round-trip of the U=90 example
  // Lower branch (Tv <= 0.283): the parabolic form gives ~50% at 196 days.
  const low = _v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: 196 });
  assert.ok(Math.abs(low.tv - 0.196) < 1e-9);
  assert.ok(Math.abs(low.u_percent - 100 * Math.sqrt(4 * 0.196 / Math.PI)) < 1e-12);
  // Exact inverse of the consolidation-time tile on both branches: feed each U through
  // the forward tile to get the time, then recover the same U here. (Values are kept off
  // the U=60 branch seam, where Terzaghi's two-branch series has an inherent ~0.35% jump.)
  for (const U of [30, 45, 75, 90]) {
    const t = _v414({ u_percent: U, cv_ft2_day: 0.1, hdr_ft: 10 }).t_days;
    assert.ok(Math.abs(_v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: t }).u_percent - U) < 1e-6);
  }
  // U approaches 100 asymptotically: strictly below at a realistic large time, and never
  // above 100 even at the float-saturation extreme (where 100 - 10^(-huge) rounds to 100).
  const late = _v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: 2000 }).u_percent;
  assert.ok(late > 99 && late < 100);
  assert.ok(_v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: 100000 }).u_percent <= 100);
  // Error seams: non-positive cv / Hdr / time, non-finite.
  assert.ok("error" in _v645({ cv_ft2_day: 0, hdr_ft: 10, t_days: 848 }));
  assert.ok("error" in _v645({ cv_ft2_day: 0.1, hdr_ft: 0, t_days: 848 }));
  assert.ok("error" in _v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: 0 }));
  assert.ok("error" in _v645({ cv_ft2_day: 0.1, hdr_ft: 10, t_days: Infinity }));
});

test("bounds: spec-v415 computeSptBearingCapacity pins both branches, the depth factor, and error seams", () => {
  const r = _v415({ n60: 20, b_ft: 6, d_ft: 2 });
  assert.ok(Math.abs(r.qa_base_ksf - (20 / 6) * Math.pow(7 / 6, 2)) < 1e-9 && r.small_footing === false);
  assert.ok(Math.abs(r.kd - (1 + 0.33 * 2 / 6)) < 1e-9);
  assert.ok(Math.abs(r.qa_ksf - r.qa_base_ksf * r.kd) < 1e-9);
  // A narrow footing uses the N60/4 branch.
  const narrow = _v415({ n60: 20, b_ft: 3, d_ft: 2 });
  assert.ok(Math.abs(narrow.qa_base_ksf - 5.0) < 1e-9 && narrow.small_footing === true);
  // The depth factor is capped at 1.33.
  assert.ok(Math.abs(_v415({ n60: 20, b_ft: 6, d_ft: 100 }).kd - 1.33) < 1e-9);
  // Error seams.
  assert.ok("error" in _v415({ n60: 0, b_ft: 6, d_ft: 2 }));
  assert.ok("error" in _v415({ n60: 20, b_ft: 0, d_ft: 2 }));
  assert.ok("error" in _v415({ n60: 20, b_ft: 6, d_ft: 0 }));
  assert.ok("error" in _v415({ n60: Infinity, b_ft: 6, d_ft: 2 }));
});

import { computeSptRequiredN60 as _v712 } from "../../calc-geotech.js";
test("bounds: spec-v712 computeSptRequiredN60 pins N60 = qa_target/qa(N60=1), round-trips through computeSptBearingCapacity, and error seams", () => {
  const r = _v712({ qa_target_ksf: 5, b_ft: 6, d_ft: 2 });
  assert.ok(!r.error, JSON.stringify(r));
  assert.ok(Math.abs(r.n60 - 19.856591) < 1e-4, `pinned N60 ~19.86: ${r.n60}`);
  assert.strictEqual(r.n60_design, 20);
  // Round-trip: at the required N60 the forward tile's allowable equals the target (both footing branches).
  for (const qa_target_ksf of [1.5, 5, 12]) {
    for (const b_ft of [3, 6, 12]) {
      for (const d_ft of [1, 2, 8]) {
        const m = _v712({ qa_target_ksf, b_ft, d_ft });
        assert.ok(!m.error, `sweep qa=${qa_target_ksf} B=${b_ft} D=${d_ft}: ${JSON.stringify(m)}`);
        assertFinite(m.n60, "n60"); assert.ok(m.n60 > 0, "n60 positive");
        const back = _v415({ n60: m.n60, b_ft, d_ft });
        assert.ok(Math.abs(back.qa_ksf - qa_target_ksf) < 1e-6, `round-trip qa=${qa_target_ksf} B=${b_ft} D=${d_ft}: ${back.qa_ksf}`);
      }
    }
  }
  // A narrow footing uses the N60/4 branch (flagged like the forward).
  assert.strictEqual(_v712({ qa_target_ksf: 5, b_ft: 3, d_ft: 2 }).small_footing, true);
  // A higher target pressure needs a higher N60.
  assert.ok(_v712({ qa_target_ksf: 8, b_ft: 6, d_ft: 2 }).n60 > r.n60);
  // Error seams: non-positive target, width, depth, non-finite.
  assert.ok("error" in _v712({ qa_target_ksf: 0, b_ft: 6, d_ft: 2 }));
  assert.ok("error" in _v712({ qa_target_ksf: 5, b_ft: 0, d_ft: 2 }));
  assert.ok("error" in _v712({ qa_target_ksf: 5, b_ft: 6, d_ft: 0 }));
  assert.ok("error" in _v712({ qa_target_ksf: Infinity, b_ft: 6, d_ft: 2 }));
});

test("bounds: spec-v416 computeLiquefactionScreening pins CSR/FS, the trigger, and error seams", () => {
  const r = _v416({ amax_g: 0.30, sigma_v_psf: 2000, sigma_vp_psf: 1200, depth_ft: 16.4042, crr: 0.20, msf: 1.0 });
  assert.ok(Math.abs(r.rd - (1 - 0.00233172 * 16.4042)) < 1e-9);
  assert.ok(Math.abs(r.csr - 0.65 * 0.30 * (2000 / 1200) * r.rd) < 1e-9);
  assert.ok(Math.abs(r.fs - r.crr / r.csr) < 1e-9 || Math.abs(r.fs - (0.20 / r.csr)) < 1e-6);
  assert.ok(r.fs < 1 && r.liquefiable === true);
  // Denser sand (higher CRR) survives.
  const dense = _v416({ amax_g: 0.30, sigma_v_psf: 2000, sigma_vp_psf: 1200, depth_ft: 16.4042, crr: 0.40, msf: 1.0 });
  assert.ok(dense.fs > 1 && dense.liquefiable === false);
  // The deep branch of rd applies below 9.15 m.
  assert.ok(Math.abs(_v416({ amax_g: 0.30, sigma_v_psf: 2000, sigma_vp_psf: 1200, depth_ft: 39.3701, crr: 0.20 }).rd - (1.174 - 0.00813816 * 39.3701)) < 1e-9);
  // Error seams: effective stress above total, non-positive, non-finite.
  assert.ok("error" in _v416({ amax_g: 0.30, sigma_v_psf: 1000, sigma_vp_psf: 1200, depth_ft: 16.4042, crr: 0.20 }));
  assert.ok("error" in _v416({ amax_g: 0.30, sigma_v_psf: 2000, sigma_vp_psf: 0, depth_ft: 16.4042, crr: 0.20 }));
  assert.ok("error" in _v416({ amax_g: 0, sigma_v_psf: 2000, sigma_vp_psf: 1200, depth_ft: 16.4042, crr: 0.20 }));
  assert.ok("error" in _v416({ amax_g: 0.30, sigma_v_psf: 2000, sigma_vp_psf: 1200, depth_ft: 16.4042, crr: Infinity }));
});

// ===================== spec-v417..v419 landscape/agriculture trio (calc-agriculture.js) =====================
import { computeMulchTopsoilVolume as _v417, computeGrainDryingEnergy as _v418, computeManureNutrientApplication as _v419 } from "../../calc-agriculture.js";

test("bounds: spec-v417 computeMulchTopsoilVolume pins the volume, bags/tons/loads, and error seams", () => {
  const r = _v417({ area_ft2: 1000, depth_in: 3, bulk_density: 1.1, bag_ft3: 2, load_yd3: 10, waste_pct: 0 });
  assert.ok(Math.abs(r.yd3 - 1000 * 0.25 / 27) < 1e-9);
  assert.strictEqual(r.bags, 125);
  assert.ok(Math.abs(r.tons - r.yd3 * 1.1) < 1e-9 && r.loads === 1);
  // Density only changes the weight, not the volume/loads.
  const mulch = _v417({ area_ft2: 1000, depth_in: 3, bulk_density: 0.5 });
  assert.ok(Math.abs(mulch.yd3 - r.yd3) < 1e-12 && Math.abs(mulch.tons - r.yd3 * 0.5) < 1e-9);
  // A waste allowance raises the volume.
  assert.ok(_v417({ area_ft2: 1000, depth_in: 3, bulk_density: 1.1, waste_pct: 10 }).yd3 > r.yd3);
  // Error seams.
  assert.ok("error" in _v417({ area_ft2: 0, depth_in: 3, bulk_density: 1.1 }));
  assert.ok("error" in _v417({ area_ft2: 1000, depth_in: 0, bulk_density: 1.1 }));
  assert.ok("error" in _v417({ area_ft2: 1000, depth_in: 3, bulk_density: 0 }));
  assert.ok("error" in _v417({ area_ft2: Infinity, depth_in: 3, bulk_density: 1.1 }));
});

test("bounds: spec-v418 computeGrainDryingEnergy pins the water/energy/propane and error seams", () => {
  const r = _v418({ bushels: 1000, lb_per_bushel: 56, mi_percent: 20, mf_percent: 15, btu_per_lb: 1500 });
  assert.ok(Math.abs(r.weight_lb - 56000) < 1e-9);
  assert.ok(Math.abs(r.water_lb - 56000 * 5 / 85) < 1e-6);
  assert.ok(Math.abs(r.propane_gal - r.energy_btu / 91500) < 1e-9 && Math.abs(r.propane_gal - 54) < 1);
  // Removing fewer points removes disproportionately less water (nonlinear).
  const less = _v418({ bushels: 1000, lb_per_bushel: 56, mi_percent: 20, mf_percent: 17.5, btu_per_lb: 1500 });
  assert.ok(Math.abs(less.water_lb - 56000 * 2.5 / 82.5) < 1e-6 && less.water_lb > r.water_lb / 2.2 && less.water_lb < r.water_lb / 1.8);
  // Error seams: final >= initial, non-positive, non-finite.
  assert.ok("error" in _v418({ bushels: 1000, lb_per_bushel: 56, mi_percent: 15, mf_percent: 15 }));
  assert.ok("error" in _v418({ bushels: 0, lb_per_bushel: 56, mi_percent: 20, mf_percent: 15 }));
  assert.ok("error" in _v418({ bushels: 1000, lb_per_bushel: 56, mi_percent: 20, mf_percent: 100 }));
  assert.ok("error" in _v418({ bushels: Infinity, lb_per_bushel: 56, mi_percent: 20, mf_percent: 15 }));
});

test("bounds: spec-v419 computeManureNutrientApplication pins the rate, co-applied P/K, and error seams", () => {
  const r = _v419({ crop_n_need_lb_acre: 150, total_n_lb_ton: 10, availability_pct: 50, p2o5_lb_ton: 5, k2o_lb_ton: 8 });
  assert.ok(Math.abs(r.avail_n_per_ton - 5) < 1e-9);
  assert.ok(Math.abs(r.rate_ton_acre - 30) < 1e-9);
  assert.ok(Math.abs(r.p2o5_applied - 150) < 1e-9 && Math.abs(r.k2o_applied - 240) < 1e-9);
  // Higher availability lowers the rate.
  const composted = _v419({ crop_n_need_lb_acre: 150, total_n_lb_ton: 10, availability_pct: 70 });
  assert.ok(Math.abs(composted.rate_ton_acre - 150 / 7) < 1e-9 && composted.rate_ton_acre < r.rate_ton_acre);
  // No P/K entered -> null co-applied.
  assert.ok(composted.p2o5_applied === null && composted.k2o_applied === null);
  // Error seams.
  assert.ok("error" in _v419({ crop_n_need_lb_acre: 0, total_n_lb_ton: 10, availability_pct: 50 }));
  assert.ok("error" in _v419({ crop_n_need_lb_acre: 150, total_n_lb_ton: 0, availability_pct: 50 }));
  assert.ok("error" in _v419({ crop_n_need_lb_acre: 150, total_n_lb_ton: 10, availability_pct: 0 }));
  assert.ok("error" in _v419({ crop_n_need_lb_acre: 150, total_n_lb_ton: 10, availability_pct: 101 }));
  assert.ok("error" in _v419({ crop_n_need_lb_acre: Infinity, total_n_lb_ton: 10, availability_pct: 50 }));
});

