import { computeFlocculationGValue as _v575 } from "../../calc-treatment.js";

test("bounds: spec-v575 computeFlocculationGValue pins the sqrt relation, the viscosity-from-temperature dependence, the Gt product, and error seams", () => {
  const r = _v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 1200 });
  assert.ok(Math.abs(r.g_value - 48) < 0.5); // sqrt(300/(0.001307*100))
  assert.ok(Math.abs(r.gt_value - 57492) < 50); // G * 1200
  assert.ok(/flocculation/.test(r.band));
  // Warm water lowers the viscosity, raising G for the same power.
  const warm = _v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: 25, detention_time_s: 1200 });
  assert.ok(Math.abs(warm.g_value - 58) < 0.5);
  assert.ok(warm.g_value > r.g_value);
  // A high power input classifies as rapid mix.
  assert.ok(/rapid mix/.test(_v575({ power_input_w: 300000, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 60 }).band));
  // The Gt product scales with the detention time.
  assert.ok(Math.abs(_v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 600 }).gt_value - r.gt_value / 2) < 1e-6);
  // Error seams: non-finite, non-positive power / volume / time, temp out of table.
  assert.ok("error" in _v575({ power_input_w: Infinity, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 1200 }));
  assert.ok("error" in _v575({ power_input_w: 0, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 1200 }));
  assert.ok("error" in _v575({ power_input_w: 300, basin_volume_m3: 0, water_temp_c: 10, detention_time_s: 1200 }));
  assert.ok("error" in _v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: 10, detention_time_s: 0 }));
  assert.ok("error" in _v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: 50, detention_time_s: 1200 }));
  assert.ok("error" in _v575({ power_input_w: 300, basin_volume_m3: 100, water_temp_c: -5, detention_time_s: 1200 }));
});

import { computeChlorineCylinderWithdrawal as _v576 } from "../../calc-treatment.js";

test("bounds: spec-v576 computeChlorineCylinderWithdrawal pins the per-container ceiling by type, the container count, the frost warning, and error seams", () => {
  const r = _v576({ feed_rate_lb_day: 100, container_type: "cylinder", room_temp_f: 70 });
  assert.ok(Math.abs(r.per_container_lb_day - 40) < 0.5); // 150-lb cylinder at 70 F
  assert.equal(r.containers, 3); // ceil(100/40)
  assert.equal(r.frost_warn, false);
  // A 1-ton container carries the same feed alone.
  const ton = _v576({ feed_rate_lb_day: 100, container_type: "ton", room_temp_f: 70 });
  assert.ok(Math.abs(ton.per_container_lb_day - 400) < 0.5);
  assert.equal(ton.containers, 1);
  // A cold room derates the ceiling and trips the frost warning.
  const cold = _v576({ feed_rate_lb_day: 100, container_type: "cylinder", room_temp_f: 45 });
  assert.ok(cold.per_container_lb_day < 40);
  assert.equal(cold.frost_warn, true);
  assert.ok(cold.containers > r.containers);
  // A single cylinder handles a feed under its ceiling.
  assert.equal(_v576({ feed_rate_lb_day: 30, container_type: "cylinder", room_temp_f: 70 }).containers, 1);
  // Error seams: non-finite, non-positive feed, bad type, sub-vaporization temp.
  assert.ok("error" in _v576({ feed_rate_lb_day: Infinity, container_type: "cylinder", room_temp_f: 70 }));
  assert.ok("error" in _v576({ feed_rate_lb_day: 0, container_type: "cylinder", room_temp_f: 70 }));
  assert.ok("error" in _v576({ feed_rate_lb_day: 100, container_type: "foo", room_temp_f: 70 }));
  assert.ok("error" in _v576({ feed_rate_lb_day: 100, container_type: "cylinder", room_temp_f: -30 }));
});

import { computeNfaFiregroundFlow as _v577 } from "../../calc-fire.js";

test("bounds: spec-v577 computeNfaFiregroundFlow pins the base flow, the exposure addition, the floor multiply, the validity flag, and error seams", () => {
  const r = _v577({ length_ft: 40, width_ft: 60, percent_involved: 50, floors_involved: 1, exposures: 2 });
  assert.ok(Math.abs(r.base_gpm - 400) < 1e-9); // (40*60/3)*0.50
  assert.ok(Math.abs(r.exposure_gpm - 200) < 1e-9); // 0.25*400*2
  assert.ok(Math.abs(r.total_gpm - 600) < 1e-9);
  assert.equal(r.valid, true); // 50% and 400 gpm within range
  // Heavy involvement drops the validity flag (defensive fire).
  const heavy = _v577({ length_ft: 40, width_ft: 60, percent_involved: 90, floors_involved: 1, exposures: 2 });
  assert.ok(Math.abs(heavy.base_gpm - 720) < 1e-9);
  assert.equal(heavy.valid, false);
  // The floor count multiplies the base.
  assert.ok(Math.abs(_v577({ length_ft: 40, width_ft: 60, percent_involved: 50, floors_involved: 2, exposures: 0 }).base_gpm - 800) < 1e-9);
  // A large base (> 1000 gpm) also drops the validity flag.
  assert.equal(_v577({ length_ft: 100, width_ft: 100, percent_involved: 50, floors_involved: 1, exposures: 0 }).valid, false);
  // Error seams: non-finite, non-positive dimensions, percent out of range, negative exposures / floors.
  assert.ok("error" in _v577({ length_ft: Infinity, width_ft: 60, percent_involved: 50 }));
  assert.ok("error" in _v577({ length_ft: 0, width_ft: 60, percent_involved: 50 }));
  assert.ok("error" in _v577({ length_ft: 40, width_ft: 0, percent_involved: 50 }));
  assert.ok("error" in _v577({ length_ft: 40, width_ft: 60, percent_involved: 0 }));
  assert.ok("error" in _v577({ length_ft: 40, width_ft: 60, percent_involved: 101 }));
  assert.ok("error" in _v577({ length_ft: 40, width_ft: 60, percent_involved: 50, floors_involved: 0 }));
  assert.ok("error" in _v577({ length_ft: 40, width_ft: 60, percent_involved: 50, exposures: -1 }));
});

import { computeRelayPumpDistance as _v578 } from "../../calc-fire.js";

test("bounds: spec-v578 computeRelayPumpDistance pins the budget, the loss per 100 ft, the max distance, the square-law, and error seams", () => {
  const r = _v578({ target_flow_gpm: 800, hose_coefficient: 0.08, max_discharge_psi: 200, intake_residual_psi: 20, elevation_ft: 10 });
  assert.ok(Math.abs(r.budget_psi - 175.66) < 1e-6); // 200 - 20 - 0.434*10
  assert.ok(Math.abs(r.fl_per_100_psi - 5.12) < 1e-9); // 0.08*(800/100)^2
  assert.ok(Math.abs(r.max_distance_ft - 3430.859375) < 1e-3);
  // Square-law: doubling the flow quarters the spacing.
  const dbl = _v578({ target_flow_gpm: 1600, hose_coefficient: 0.08, max_discharge_psi: 200, intake_residual_psi: 20, elevation_ft: 10 });
  assert.ok(Math.abs(dbl.max_distance_ft - r.max_distance_ft / 4) < 1e-6);
  // Downhill (negative elevation) increases the budget.
  assert.ok(_v578({ target_flow_gpm: 800, hose_coefficient: 0.08, max_discharge_psi: 200, intake_residual_psi: 20, elevation_ft: -10 }).budget_psi > r.budget_psi);
  // Error seams: non-finite, non-positive flow / coefficient / max discharge, exhausted budget.
  assert.ok("error" in _v578({ target_flow_gpm: Infinity, hose_coefficient: 0.08, max_discharge_psi: 200 }));
  assert.ok("error" in _v578({ target_flow_gpm: 0, hose_coefficient: 0.08, max_discharge_psi: 200 }));
  assert.ok("error" in _v578({ target_flow_gpm: 800, hose_coefficient: 0, max_discharge_psi: 200 }));
  assert.ok("error" in _v578({ target_flow_gpm: 800, hose_coefficient: 0.08, max_discharge_psi: 0 }));
  assert.ok("error" in _v578({ target_flow_gpm: 800, hose_coefficient: 0.08, max_discharge_psi: 200, intake_residual_psi: 250, elevation_ft: 0 }));
});

import { computeDraftLiftMax as _v579 } from "../../calc-fire.js";

test("bounds: spec-v579 computeDraftLiftMax pins the theoretical lift, the attainable lift, the altitude correction, the suction-loss subtraction, and error seams", () => {
  const r = _v579({ site_elevation_ft: 3000, pump_factor: 0.667, suction_losses_ft: 0 });
  assert.ok(Math.abs(r.theoretical_lift_ft - 30.9) < 1e-9); // 33.9 - 3000/1000
  assert.ok(Math.abs(r.attainable_lift_ft - 0.667 * 30.9) < 1e-9);
  // Higher altitude loses more to the thinner atmosphere.
  const high = _v579({ site_elevation_ft: 8000, pump_factor: 0.667, suction_losses_ft: 0 });
  assert.ok(Math.abs(high.theoretical_lift_ft - 25.9) < 1e-9);
  assert.ok(high.attainable_lift_ft < r.attainable_lift_ft);
  // Suction losses subtract directly from the attainable lift.
  assert.ok(Math.abs(_v579({ site_elevation_ft: 3000, pump_factor: 0.667, suction_losses_ft: 2 }).attainable_lift_ft - (0.667 * 30.9 - 2)) < 1e-9);
  // Error seams: non-finite, negative elevation / losses, factor out of (0,1].
  assert.ok("error" in _v579({ site_elevation_ft: Infinity, pump_factor: 0.667 }));
  assert.ok("error" in _v579({ site_elevation_ft: -1, pump_factor: 0.667 }));
  assert.ok("error" in _v579({ site_elevation_ft: 3000, pump_factor: 0.667, suction_losses_ft: -1 }));
  assert.ok("error" in _v579({ site_elevation_ft: 3000, pump_factor: 0 }));
  assert.ok("error" in _v579({ site_elevation_ft: 3000, pump_factor: 1.5 }));
});

import { computeTankerShuttleFlow as _v580 } from "../../calc-fire.js";

