  assert.ok("error" in _v580({ nominal_tank_gal: 3000, usable_fraction: 0, tanker_count: 3, cycle_time_min: 12 }));
  assert.ok("error" in _v580({ nominal_tank_gal: 3000, usable_fraction: 0.9, tanker_count: 0, cycle_time_min: 12 }));
